31	const SYNC_ALARM = 'auxilio-sync';
32	const BADGE_COLOR = '#92288E';
33	// Cross-channel status poll throttle: don't ask the engine "which are handled"
34	// every alarm tick. Poll when the pending iCalUid set changes, else at most this
35	// often. Stored in storage.local so the throttle survives SW restarts.
36	const STATUS_POLL_KEY = 'auxilio.statusPoll';
37	const STATUS_POLL_INTERVAL_MS = 5 * 60_000;
38	// Muted/error badge for a recoverable auth lapse — visually distinct from the
39	// brand-tinted visitor-count badge so "nudging is offline" never reads as a count.
40	const LAPSED_BADGE_COLOR = '#B3261E';
41	
42	// Whether the side panel is currently open (a port is connected). Content
43	// scripts ask for this on (re)load so auto-follow works after navigation.
44	let panelConnected = false;
45	
46	export default defineBackground(() => {
47	  // Let content scripts read/write storage.session (default is trusted-only).
48	  // Needed for the active-event handoff + nudge-dismissal persistence.
49	  chrome.storage.session
50	    .setAccessLevel({ accessLevel: 'TRUSTED_AND_UNTRUSTED_CONTEXTS' })
51	    .catch((err) => console.warn('[auxilio] setAccessLevel failed', err));
52	
53	  // Toolbar icon opens the panel (Chrome's required user gesture).
54	  chrome.sidePanel
55	    .setPanelBehavior({ openPanelOnActionClick: true })
56	    .catch((err) => console.error('[auxilio] setPanelBehavior failed', err));
57	
58	  // Durable, official change-detection: poll on an alarm (no DOM).
59	  chrome.alarms.create(SYNC_ALARM, { periodInMinutes: 1 });
60	  chrome.runtime.onInstalled.addListener(() => {
61	    chrome.alarms.create(SYNC_ALARM, { periodInMinutes: 1 });
62	    // Only force a full tokenless re-scan when the sync-relevant config actually
63	    // changed (magic address / query schema) — incremental never re-reports an
64	    // already-consumed change, so a real config change needs the token dropped.
65	    // A plain reload keeps the token and resumes cheap incremental sync, instead
66	    // of paying the multi-second full forward-window scan (which the MV3 worker
67	    // can be killed mid-flight) on every reload. The 12h re-scan self-heals drift.
68	    void syncConfigChanged().then((changed) =>
69	      (changed ? clearSyncToken() : Promise.resolve()).then(() => doSync()),
70	    );
71	  });
72	  chrome.runtime.onStartup.addListener(() => void doSync());
73	  chrome.alarms.onAlarm.addListener((a) => {
74	    if (a.name === SYNC_ALARM) void doSync();
75	  });
76	  chrome.notifications.onClicked.addListener((id) => chrome.notifications.clear(id));
77	
78	  // Track the side panel open/closed via a port it connects on mount, and tell
79	  // calendar tabs so the in-page button can hide while the panel is open.
80	  chrome.runtime.onConnect.addListener((port) => {
81	    if (port.name !== SIDEPANEL_PORT) return;
82	    panelConnected = true;
83	    broadcastPanelState(true);
84	    port.onDisconnect.addListener(() => {
85	      panelConnected = false;
86	      broadcastPanelState(false);
87	    });
88	  });
