90	  chrome.runtime.onMessage.addListener((msg: RpcRequest, sender, sendResponse) => {
91	    if (typeof msg?.type === 'string' && msg.type.startsWith('__')) return false; // broadcasts
92	    handle(msg, sender)
93	      .then(sendResponse)
94	      .catch((err) => sendResponse(fail(err)));
95	    return true; // async response
96	  });
97	
98	  console.log('[auxilio] background ready');
99	});
100	
101	// ─────────────────────────── sync loop ───────────────────────────
102	
103	async function doSync(): Promise<void> {
104	  let tokens: { idToken: string; accessToken: string };
105	  try {
106	    tokens = await getValidTokens();
107	  } catch {
108	    // Token unavailable. If the user was connected, this is a recoverable lapse
109	    // (storage.session wiped on restart, or silent renew failed) — surface it so
110	    // nudging never dies silently. If they never connected, stay quiet.
111	    if (await wasConnected()) await setLapsed(true);
112	    return;
113	  }
114	  let result;
115	  try {
116	    result = await runSync(tokens.accessToken);
117	  } catch (err) {
118	    console.warn('[auxilio] sync failed', err);
119	    return;
120	  }
121	
122	  // Got here with working tokens → any prior lapse is over.
123	  await setLapsed(false);
124	
125	  // Cross-channel suppression: ask the engine which marked events already have an
126	  // active pass (issued via the add-on or another device), so we don't nag for
127	  // them. Gated/throttled so this isn't a per-minute engine call.
128	  const engineHandled = await maybePollEngineStatus(tokens.idToken);
129	
130	  // Toolbar badge = distinct visitor events still needing passes (engine-filtered,
131	  // series-collapsed) — sourced from listMarked so it matches the banner exactly.
132	  const targets = await listMarked();
133	  await chrome.action.setBadgeBackgroundColor({ color: BADGE_COLOR });
134	  await chrome.action.setBadgeText({ text: targets.length > 0 ? String(targets.length) : '' });
135	
136	  // OS notification for each newly-discovered visitor event (out-of-tab alert) —
137	  // but never for one the engine has already handled elsewhere.
138	  for (const ev of result.newMarked) {
139	    if (!engineHandled.has((ev.iCalUid ?? '').toLowerCase())) notifyVisitorEvent(ev);
140	  }
141	
142	  // In-page nudge banner: push the current marked set to calendar tabs, plus
143	  // any events that just stopped being pending (deleted/cancelled) so the page
144	  // can purge stale optimistic nudges for them.
145	  broadcastNudge(targets, result.cancelledIds);
146	
147	  // If the event the panel is showing changed (post-save), tell it to refetch.
148	  const stored = await chrome.storage.session.get(ACTIVE_EID_KEY);
149	  const activeEid = stored[ACTIVE_EID_KEY] as string | undefined;
150	  if (activeEid) {
151	    const dec = decodeEid(activeEid);
152	    if (dec && result.changedIds.has(dec.eventId)) broadcastRefreshActive();
153	  }
154	}
155	
156	/** Ask the engine which pending events already have an active pass (handled via
157	 *  any surface), and cache the answer. Throttled: re-polls when the pending set
158	 *  changes, else at most every STATUS_POLL_INTERVAL_MS. Degrades gracefully — if
159	 *  the engine/route is unreachable it keeps the last known set (local-only
160	 *  suppression still works). Returns the (lower-cased) engine-handled set. */
161	async function maybePollEngineStatus(idToken: string): Promise<Set<string>> {
162	  const uids = await listPendingICalUids();
163	  if (uids.length === 0) {
164	    await setEngineHandled([]); // nothing pending → clear the cache
165	    return new Set();
166	  }
167	  const sig = [...uids].sort().join('|');
168	  const store = await chrome.storage.local.get(STATUS_POLL_KEY);
169	  const last = store[STATUS_POLL_KEY] as { at: number; sig: string } | undefined;
170	  const fresh = last && Date.now() - last.at < STATUS_POLL_INTERVAL_MS;
171	  if (last && last.sig === sig && fresh) return readEngineHandled(); // reuse cache
172	
173	  // Stamp the throttle now (before the call) so a missing/erroring route backs off
174	  // instead of retrying every tick. A changed signature still forces a re-poll.
175	  await chrome.storage.local.set({ [STATUS_POLL_KEY]: { at: Date.now(), sig } });
176	  try {
177	    const { active } = await engine.status(idToken, uids);
178	    await setEngineHandled(active);
179	    return new Set(active.map((u) => u.toLowerCase()));
180	  } catch (err) {
181	    console.warn('[auxilio] engine status poll failed; keeping last known', err);
182	    return readEngineHandled();
183	  }
184	}
185	
186	function broadcastPanelState(open: boolean): void {
187	  sendToCalendarTabs({ type: PANEL_STATE, open });
188	}
189	
190	function broadcastNudge(targets: VisitorEventSummary[], cancelled: string[] = []): void {
191	  sendToCalendarTabs({ type: NUDGE_TARGETS, targets, cancelled });
192	}
193	
194	/** Enter/leave the recoverable auth-lapsed state: a distinct toolbar badge plus a
195	 *  broadcast that drives the in-page "Reconnect" banner. Broadcast unconditionally
196	 *  so a calendar tab loaded mid-lapse learns about it on the next sync. */
197	async function setLapsed(lapsed: boolean): Promise<void> {
198	  if (lapsed) {
199	    await chrome.action.setBadgeBackgroundColor({ color: LAPSED_BADGE_COLOR });
200	    await chrome.action.setBadgeText({ text: '!' });
201	  }
202	  sendToCalendarTabs({ type: AUTH_LAPSED, lapsed });
203	}
204	
205	/** Recompute the nudge surfaces from local state (no Calendar round-trip) — used
206	 *  after a send marks an event handled, so the badge/banner drop it immediately. */
207	async function refreshNudgeSurfaces(): Promise<void> {
208	  const targets = await listMarked();
209	  await chrome.action.setBadgeBackgroundColor({ color: BADGE_COLOR });
210	  await chrome.action.setBadgeText({ text: targets.length > 0 ? String(targets.length) : '' });
211	  broadcastNudge(targets);
212	}
