214	function sendToCalendarTabs(message: unknown): void {
215	  chrome.tabs
216	    .query({ url: 'https://calendar.google.com/*' })
217	    .then((tabs) => {
218	      for (const t of tabs) {
219	        if (t.id != null) chrome.tabs.sendMessage(t.id, message).catch(() => {});
220	      }
221	    })
222	    .catch(() => {});
223	}
224	
225	function notifyVisitorEvent(ev: VisitorEventSummary): void {
226	  chrome.notifications.create(`auxilio:${ev.eventId}`, {
227	    type: 'basic',
228	    iconUrl: chrome.runtime.getURL('icon/128.png'),
229	    title: 'Visitor event',
230	    message: `${ev.title}. Open Auxilio to register passes.`,
231	    priority: 1,
232	  });
233	}
234	
235	// ─────────────────────────── RPC plumbing ───────────────────────────
236	
237	const ok = <T,>(data: T): RpcResponse<T> => ({ ok: true, data });
238	
239	function fail(err: unknown): RpcResponse<never> {
240	  const message = err instanceof Error ? err.message : String(err);
241	  const status = err instanceof EngineError ? err.status : undefined;
242	  return { ok: false, error: message, status, needsAuth: status === 401 };
243	}
244	
245	async function withTokens<T>(
246	  fn: (t: { idToken: string; accessToken: string; email?: string }) => Promise<T>,
247	): Promise<RpcResponse<T>> {
248	  let tokens;
249	  try {
250	    tokens = await getValidTokens();
251	  } catch {
252	    return { ok: false, error: 'Sign in to continue.', needsAuth: true };
253	  }
254	  try {
255	    return ok(await fn(tokens));
256	  } catch (err) {
257	    return fail(err);
258	  }
259	}
260	
261	const withIdToken = <T,>(fn: (idToken: string) => Promise<T>) =>
262	  withTokens((t) => fn(t.idToken));
263	
264	async function handle(
265	  msg: RpcRequest,
266	  sender: chrome.runtime.MessageSender,
267	): Promise<RpcResponse<unknown>> {
268	  switch (msg.type) {
269	    case 'AUTH_STATUS':
270	      return ok(await authStatus());
271	    case 'AUTH_SIGN_IN': {
272	      const status = await signIn();
273	      void doSync(); // warm the marked set + badge right after sign-in
274	      return ok(status);
275	    }
276	    case 'AUTH_SIGN_OUT':
277	      await signOut();
278	      await chrome.action.setBadgeText({ text: '' });
279	      return ok({ signedIn: false });
280	
281	    case 'OPEN_PANEL': {
282	      // Open the side panel within the in-page click's user activation (e.g. the
283	      // "Reconnect" banner) so the user lands on the sign-in gate. No active event.
284	      const tabId = sender.tab?.id;
285	      let opened = false;
286	      if (!panelConnected && tabId != null) {
287	        try {
288	          await chrome.sidePanel.open({ tabId });
289	          opened = true;
290	        } catch (err) {
291	          console.warn('[auxilio] sidePanel.open failed (gesture not carried?)', err);
292	        }
293	      }
294	      return ok({ opened });
295	    }
296	
297	    case 'OPEN_FOR_EVENT': {
298	      // The background is the single authority on open-vs-follow: panelConnected
299	      // (the panel's own port) is the truth, so the content script no longer
300	      // guesses with local flags that drift. Open the panel only when it isn't
301	      // already connected — otherwise this is just a "follow" and we fall through
302	      // to update the active event below. Call sidePanel.open FIRST, before any
303	      // await, so the content-script click's user activation is still valid
304	      // (sidePanel.open requires a live gesture).
305	      const tabId = sender.tab?.id;
306	      let opened = false;
307	      if (!panelConnected && tabId != null) {
308	        try {
309	          await chrome.sidePanel.open({ tabId });
310	          opened = true;
311	        } catch (err) {
312	          console.warn('[auxilio] sidePanel.open failed (gesture not carried?)', err);
313	        }
314	      }
315	      // Store after — the panel reacts to this via storage.onChanged either way.
316	      // The DOM snapshot lets the panel paint instantly + cover the unsaved case.
317	      await chrome.storage.session.set({
318	        [ACTIVE_EID_KEY]: msg.eid,
319	        [ACTIVE_SNAPSHOT_KEY]: msg.snapshot ?? null,
320	      });
321	      return ok({ opened });
322	    }
323	
324	    case 'FOLLOW_EVENT': {
325	      // Auto-follow: point the (already open) panel at the event the user is
326	      // viewing — no sidePanel.open. The panel applies its own busy-guard.
327	      await chrome.storage.session.set({
328	        [ACTIVE_EID_KEY]: msg.eid,
329	        [ACTIVE_SNAPSHOT_KEY]: msg.snapshot ?? null,
330	      });
331	      return ok({ followed: true });
332	    }
333	
334	    case 'RESOLVE_EVENT':
335	      return withTokens((t) => fetchActiveEvent(msg.eid, t.accessToken));
336	
337	    case 'DRAFT_LOAD':
338	      return withIdToken((t) => engine.loadDraft(t, msg.event));
339	    case 'RESOLVE_GUESTS':
340	      // Best-effort People API name/photo lookup with the host's access_token.
341	      return withTokens((t) => resolveGuests(t.accessToken, msg.emails));
342	    case 'DRAFT_PATCH':
343	      return withIdToken((t) => engine.patchDraft(t, msg.iCalUid, msg.patch));
344	    case 'PREVIEW':
345	      return withIdToken((t) => engine.preview(t, msg.iCalUid, msg.visitorEmail));
346	    case 'SEND':
347	      return withTokens(async (t) => {
348	        const result = await engine.send(t.idToken, msg.iCalUid, msg.start, msg.end);
349	        // Passes are now issued (or remain issued after an update) → drop this
350	        // event from the nudge surfaces. Prefer the event id we already hold
351	        // locally (the active eid — exactly the key the marked set uses); fall
352	        // back to the engine's echoed providerEventId. Not relying on the echo
353	        // closes a silent gap where a draft without providerEventId would never
354	        // get suppressed.
355	        if (result.activeCount > 0) {
356	          const stored = await chrome.storage.session.get(ACTIVE_EID_KEY);
357	          const eid = stored[ACTIVE_EID_KEY] as string | undefined;
358	          const eventId = (eid && decodeEid(eid)?.eventId) || result.draft.providerEventId;
359	          if (eventId) {
360	            await markHandled(eventId);
361	            await refreshNudgeSurfaces();
362	          }
363	        }
364	        return result;
365	      });
366	    case 'CANCEL_GUEST':
367	      return withIdToken((t) =>
368	        engine.cancelGuest(t, msg.iCalUid, msg.invitationId),
369	      );
370	
371	    case 'LIST_VISITOR_EVENTS':
372	      return withTokens(async (t) => {
373	        // A refresh hiccup (a transient Calendar API error) must not blank the
374	        // list — serve the last-known marked set instead of failing the query.
375	        try {
376	          await runSync(t.accessToken); // refresh before listing
377	        } catch (err) {
378	          console.warn('[auxilio] LIST_VISITOR_EVENTS refresh failed; serving cached set', err);
379	        }
380	        // Homescreen is a management surface: list pending AND already-sent events
381	        // (tagged status) — unlike the nag surfaces, which use listMarked.
382	        return listForPanel();
383	      });
384	
385	    case 'GET_NUDGE_TARGETS':
386	      // Cheap read of the last-synced marked set (no token / no sync) — lets the
387	      // content script seed its banner immediately on page load.
388	      return ok(await listMarked());
389	
390	    case 'IS_EVENT_HANDLED':
391	      // Lets the in-page optimistic nudge skip an event whose passes were already
392	      // sent from this extension (the sync filters these, the optimistic path can't).
393	      return ok({ handled: await isEventHandled(msg.eventId) });
394	
395	    case 'IS_NUDGE_WORTHY':
396	      // The in-page OPTIMISTIC nudge (the instant, DOM-derived guess) exists ONLY to
397	      // bridge sync lag for a brand-new event. So suppress it for anything the sync
398	      // already knows about:
399	      //  - isEventHandled → passes were already sent from this extension; and
400	      //  - isEventMarked  → the event is already in the marked set, i.e. a pending
401	      //    event the sync banner already covers (and whose dismissal the content
402	      //    script remembers) OR an already-handled one.
403	      // This is what stops an already-sent / already-dismissed event from nudging
404	      // again when it's reopened and closed after a page refresh. Only a genuinely
405	      // new event (in neither set) reaches the organizer check below.
406	      return withTokens(async (t) => {
407	        if (await isEventHandled(msg.eventId)) return { worthy: false };
408	        if (await isEventMarked(msg.eventId)) return { worthy: false };
409	        // Brand-new event the sync hasn't caught yet: confirm the signed-in user is
410	        // the ORGANIZER (not a guest) before the instant nudge. events.get may 404 on
411	        // a just-created event → assume worthy (the host's own new event); the
412	        // organizer-gated background sync reconciles it moments later.
413	        try {
414	          const ev = await fetchActiveEvent(msg.eid, t.accessToken);
415	          const me = (t.email ?? (await authStatus()).email ?? '').toLowerCase();
416	          const org = (ev.organizerEmail ?? '').toLowerCase();
417	          if (!org || !me) return { worthy: true };
418	          return { worthy: org === me };
419	        } catch {
420	          return { worthy: true };
421	        }
422	      });
423	
424	    case 'SYNC_NOW':
425	      // On-demand sync (page load / tab focus / just left the editor) so the
426	      // banner appears fast instead of waiting up to a minute for the alarm.
427	      await doSync();
428	      return ok({ synced: true });
429	
430	    case 'GET_PANEL_STATE':
431	      return ok({ open: panelConnected });
432	
433	    case 'NAVIGATE_TO_EVENT':
434	      return withTokens(async (t) => {
435	        // Open the event's full EDIT screen (/r/eventedit/<eid>) in the existing
436	        // calendar tab — same tab, no new tab. The button passes a ready eid
437	        // (from the page's data-eventid); the nudge passes eventId to encode
438	        // (sync events only carry the id; primary calendar id = the user's email).
439	        let editEid = msg.eid;
440	        if (!editEid && msg.eventId) {
441	          const email = t.email ?? (await authStatus()).email ?? 'primary';
442	          editEid = encodeEid(msg.eventId, email);
443	        }
444	        // The web editor needs the *real* calendar id in the eid — for the
445	        // primary calendar that's the user's email, not the literal "primary"
446	        // (which the Calendar API accepts but the /eventedit URL can't resolve).
447	        // Sync/nudge eids are encoded with "primary", so rewrite them here.
448	        if (editEid) {
449	          const dec = decodeEid(editEid);
450	          if (dec && (dec.calendarId === 'primary' || !dec.calendarId)) {
451	            const email = t.email ?? (await authStatus()).email;
452	            if (email) editEid = encodeEid(dec.eventId, email);
453	          }
454	        }
455	        // Google's eventedit eid is base64 with padding stripped — normalize the
456	        // raw data-eventid (which may carry `=` padding) to match.
457	        if (editEid) editEid = editEid.replace(/=+$/, '');
458	        if (!editEid) return { navigated: false };
459	        const tabs = await chrome.tabs.query({ url: 'https://calendar.google.com/*' });
460	        const tab = tabs.find((x) => x.active) ?? tabs[0];
461	        if (tab?.id == null || !tab.url) return { navigated: false };
462	        // Build the edit-screen URL from the /u/<n>/ account segment.
463	        const u = tab.url.match(/\/calendar\/(u\/\d+\/)?/);
464	        const userSeg = u?.[1] ?? '';
465	        const url = `https://calendar.google.com/calendar/${userSeg}r/eventedit/${editEid}`;
466	        console.log('[auxilio] navigate →', { from: tab.url, to: url, editEid });
467	        await chrome.tabs.update(tab.id, { url, active: true });
468	        return { navigated: true };
469	      });
470	
471	    default:
472	      return { ok: false, error: 'Unknown request' };
473	  }
474	}
