1	/**
2	 * Calendar sync (background only). The durable, official "what changed" engine:
3	 * runs on a chrome.alarm, lists changes via a sync token, and maintains the set
4	 * of upcoming visitor (magic-address) events in storage.local. Drives:
5	 *  - post-save refresh of the open event (changedIds),
6	 *  - the visitor-event notification + toolbar badge (newMarked / count),
7	 *  - the side panel's "open from list" picker (listMarked).
8	 * No DOM. Reflects SAVED state only (pre-save edits are add-on-only — see
9	 * Planning-docs/2026-06-19_calendar_addon_vs_extension_capabilities.md).
10	 */
11	import { MAGIC_ADDRESS } from './config';
12	import { encodeEid, isMarked, listEvents } from './calendar';
13	import type { PanelVisitorEvent, VisitorEventSummary } from './types';
14	
15	const SYNC_TOKEN_KEY = 'auxilio.syncToken';
16	const MARKED_KEY = 'auxilio.markedEvents';
17	/** Events the user has already issued passes for from this extension — keyed by
18	 *  eventId, value = when handled. A durable overlay over the marked set so a
19	 *  finished event stops badging/notifying/nudging instead of nagging until it
20	 *  ages out. Local-only signal: passes sent via the add-on or another device
21	 *  won't appear here (full cross-channel truth needs an engine status endpoint —
22	 *  deferred). Pruned by HANDLED_TTL_MS. */
23	const HANDLED_KEY = 'auxilio.handledEvents';
24	/** iCalUids the ENGINE reports already have an active pass — i.e. handled through
25	 *  ANY surface (add-on, another device), not just this extension. Overwritten on
26	 *  each status poll (NOT durable like HANDLED_KEY): if passes are later cancelled
27	 *  elsewhere, the next poll drops the uid and the event correctly resurfaces. */
28	const ENGINE_HANDLED_KEY = 'auxilio.engineHandled';
29	/** When the last FULL (tokenless) re-scan ran. Incremental sync only reports
30	 *  changes, so an event missed when its change was first consumed (e.g. a
31	 *  different magic address in an earlier build) is never re-examined until a full
32	 *  re-scan. We force one periodically + on install so the set self-heals. */
33	const LAST_FULL_KEY = 'auxilio.lastFullSync';
34	/** Signature of the sync-relevant config (magic address + query schema) at the
35	 *  last run, so a plain reload can resume incremental sync instead of paying the
36	 *  full forward-window scan every time. See syncConfigChanged. */
37	const CONFIG_SIG_KEY = 'auxilio.configSig';
38	/** Bump when the events.list query SHAPE changes (e.g. adding timeMax) so the next
39	 *  load does one clean full re-scan to rebuild the marked set under the new query.
40	 *  v2 = bounded forward window (timeMax). v3 = organizer-only gate — forces a clean
41	 *  re-scan that drops events the user is merely a GUEST of, which earlier builds
42	 *  wrongly marked + nudged. */
43	const SYNC_SCHEMA_VERSION = 3;
44	const PAST_GRACE_MS = 60 * 60_000; // keep events until 1h after they end
45	const HANDLED_TTL_MS = 30 * 24 * 60 * 60_000; // forget "handled" after 30 days
46	const FULL_RESYNC_INTERVAL_MS = 12 * 60 * 60_000; // re-scan the whole window twice a day
47	
48	type MarkedMap = Record<string, VisitorEventSummary>;
49	type HandledMap = Record<string, number>;
50	
51	async function readMarked(): Promise<MarkedMap> {
52	  const r = await chrome.storage.local.get(MARKED_KEY);
53	  return (r[MARKED_KEY] as MarkedMap) ?? {};
54	}
55	
56	async function readHandled(): Promise<HandledMap> {
57	  const r = await chrome.storage.local.get(HANDLED_KEY);
58	  return (r[HANDLED_KEY] as HandledMap) ?? {};
59	}
60	
61	/** Drop the sync token so the next sync does a full tokenless re-scan of the
62	 *  forward window. Called on a real config change so it takes effect immediately
63	 *  instead of waiting for the periodic resync. */
64	export async function clearSyncToken(): Promise<void> {
65	  await chrome.storage.local.remove([SYNC_TOKEN_KEY, LAST_FULL_KEY]);
66	}
67	
68	/** Did the sync-relevant config (magic address or query schema) change since the
69	 *  last run? That's the ONLY time we must drop the token for a full re-scan. A
70	 *  plain reload leaves the signature unchanged, so it keeps the token and resumes
71	 *  cheap incremental sync — instead of re-running the multi-second full scan (which
72	 *  the MV3 worker can be killed in the middle of) on every reload. Records the new
73	 *  signature as a side effect. The 12h periodic full re-scan still self-heals drift. */
74	export async function syncConfigChanged(): Promise<boolean> {
75	  const sig = `${MAGIC_ADDRESS}|v${SYNC_SCHEMA_VERSION}`;
76	  const r = await chrome.storage.local.get(CONFIG_SIG_KEY);
77	  if (r[CONFIG_SIG_KEY] === sig) return false;
78	  await chrome.storage.local.set({ [CONFIG_SIG_KEY]: sig });
79	  return true;
80	}
81	
82	/** Record that passes were issued for this event — drops it from every nudge
83	 *  surface (badge, banner, notification, picker) until it ages out. */
84	export async function markHandled(eventId: string): Promise<void> {
85	  if (!eventId) return;
86	  const handled = await readHandled();
87	  handled[eventId] = Date.now();
88	  await chrome.storage.local.set({ [HANDLED_KEY]: handled });
89	}
90	
91	export async function readEngineHandled(): Promise<Set<string>> {
92	  const r = await chrome.storage.local.get(ENGINE_HANDLED_KEY);
93	  return new Set((r[ENGINE_HANDLED_KEY] as string[]) ?? []);
94	}
95	
96	/** Has this event already been handled (passes issued) from THIS extension? Reads
97	 *  the local handled overlay — lets the in-page optimistic nudge skip an event the
98	 *  user already sent passes for, instead of re-nudging when they reopen/close it
99	 *  (the sync set already filters handled events, but the optimistic DOM guess
100	 *  bypasses that filter). engineHandled isn't consulted here: it's keyed by iCalUid,
101	 *  which the optimistic path doesn't have. */
102	export async function isEventHandled(eventId: string): Promise<boolean> {
103	  if (!eventId) return false;
104	  const handled = await readHandled();
105	  return !!handled[eventId];
106	}
107	
108	/** iCalUids of marked events that aren't LOCALLY handled — the candidate set to
109	 *  ask the engine about. Deliberately ignores engineHandled: we must keep asking
110	 *  about already-engine-handled events so a pass cancelled elsewhere is re-detected
111	 *  and the event resurfaces. */
112	export async function listPendingICalUids(): Promise<string[]> {
113	  const [marked, handled] = await Promise.all([readMarked(), readHandled()]);
114	  const uids = new Set<string>();
115	  for (const m of Object.values(marked)) {
116	    if (handled[m.eventId]) continue;
117	    if (m.iCalUid) uids.add(m.iCalUid);
118	  }
119	  return [...uids];
120	}
121	
122	/** Replace the engine-handled iCalUid set with the latest status answer. Overwrite
123	 *  (not merge) so events whose passes were cancelled elsewhere drop out and
124	 *  resurface. Lower-cased for case-insensitive matching against marked iCalUids. */
125	export async function setEngineHandled(iCalUids: string[]): Promise<void> {
126	  await chrome.storage.local.set({
127	    [ENGINE_HANDLED_KEY]: [...new Set(iCalUids.map((u) => u.toLowerCase()))],
128	  });
129	}
130	
131	export interface SyncResult {
132	  changedIds: Set<string>;
133	  newMarked: VisitorEventSummary[];
134	  /** Events seen this cycle that are no longer pending visitor events (deleted/
135	   *  cancelled). Lets the in-page nudge purge stale optimistic guesses. */
136	  cancelledIds: string[];
137	  markedCount: number;
138	}
139	
140	/** Coalesce concurrent syncs (the 1-minute alarm + on-demand LIST/SYNC_NOW) so
141	 *  they can't race on the shared sync token / marked map and lose an update — both
142	 *  read the same baseline, both write at the end, and the later write clobbers the
143	 *  earlier one (an event one run marked can vanish, and won't be re-reported once
144	 *  the token advances). One in-flight sync at a time removes that hazard. */
145	let inFlight: Promise<SyncResult> | null = null;
146	export function runSync(accessToken: string): Promise<SyncResult> {
147	  if (inFlight) return inFlight;
148	  inFlight = doRunSync(accessToken).finally(() => {
149	    inFlight = null;
150	  });
151	  return inFlight;
152	}
