154	/** Pull changes since the last sync; update the marked set; report deltas. */
155	async function doRunSync(accessToken: string): Promise<SyncResult> {
156	  const store = await chrome.storage.local.get([
157	    SYNC_TOKEN_KEY,
158	    MARKED_KEY,
159	    HANDLED_KEY,
160	    ENGINE_HANDLED_KEY,
161	    LAST_FULL_KEY,
162	  ]);
163	  const engineHandled = new Set((store[ENGINE_HANDLED_KEY] as string[]) ?? []);
164	  // The set we knew BEFORE this sync — the baseline for "what's genuinely new"
165	  // (so a full re-scan that re-discovers the whole window doesn't re-notify).
166	  const prevMarked = (store[MARKED_KEY] as MarkedMap) ?? {};
167	  const handled = (store[HANDLED_KEY] as HandledMap) ?? {};
168	  const lastFull = (store[LAST_FULL_KEY] as number) ?? 0;
169	
170	  let syncToken = store[SYNC_TOKEN_KEY] as string | undefined;
171	  // Force a periodic full re-scan: incremental sync never re-reports an event
172	  // whose change was already consumed, so a once-missed event (wrong magic
173	  // address in a past build, a transient attendee trim) would stay invisible
174	  // forever. Dropping the token re-evaluates the whole forward window.
175	  if (syncToken && Date.now() - lastFull > FULL_RESYNC_INTERVAL_MS) {
176	    syncToken = undefined;
177	  }
178	
179	  let resp = await listEvents(accessToken, { syncToken });
180	  if (resp.expired) {
181	    // Token stale → full resync from scratch.
182	    syncToken = undefined;
183	    resp = await listEvents(accessToken, {});
184	  }
185	  // A tokenless call re-scanned the full window; rebuild the set from scratch so
186	  // stale/no-longer-marked events drop out. Incremental carries the set forward.
187	  const fullSync = !syncToken;
188	  const marked: MarkedMap = fullSync ? {} : { ...prevMarked };
189	
190	  const changedIds = new Set<string>();
191	  const newMarked: VisitorEventSummary[] = [];
192	  const cancelledIds: string[] = [];
193	
194	  // Series we already tracked (any previously-marked instance) — so a newly
195	  // discovered later occurrence of a known recurring event, OR a full re-scan
196	  // that re-finds the whole window, doesn't fire a fresh notification.
197	  const knownSeries = new Set(
198	    Object.values(prevMarked).map((m) => m.seriesId ?? m.eventId),
199	  );
200	  // Series notified within THIS cycle — collapses an initial sync that discovers
201	  // dozens of weekly instances at once down to a single notification.
202	  const notifiedSeries = new Set<string>();
203	
204	  for (const ev of resp.items) {
205	    if (!ev.id) continue;
206	    changedIds.add(ev.id);
207	    const cancelled = ev.status === 'cancelled';
208	    const hasMagic = isMarked(ev);
209	    // DIAGNOSTIC: the magic address is somewhere in this event's payload, yet
210	    // isMarked() didn't flag it — i.e. it's not a structured attendee email and
211	    // not in `location` (e.g. it's only in the description, or events.list
212	    // returned a trimmed attendee list). This is the signature of a primary-
213	    // calendar miss; the warning shows exactly what we got back.
214	    if (!hasMagic && MAGIC_ADDRESS && JSON.stringify(ev).toLowerCase().includes(MAGIC_ADDRESS)) {
