216	        '[auxilio] sync MISS: magic address in payload but isMarked() is false',
217	        { id: ev.id, summary: ev.summary, location: ev.location, attendees: ev.attendees, status: ev.status },
218	      );
219	    }
220	    // Only the event's ORGANIZER (the host) registers visitors. A guest who was
221	    // merely invited to a visitor event sees the magic address among the attendees
222	    // on THEIR copy too — but they must never be nudged/badged/notified to "manage"
