224	    // authoritative "this calendar's user owns the event" flag.
225	    const marked_ = hasMagic && ev.organizer?.self === true;
226	    if (marked_ && !cancelled) {
227	      const seriesId = ev.recurringEventId || ev.id;
228	      const summary: VisitorEventSummary = {
229	        eid: encodeEid(ev.id, 'primary'),
230	        eventId: ev.id,
231	        iCalUid: ev.iCalUID ?? '',
232	        title: ev.summary || '(no title)',
233	        start: ev.start?.dateTime ?? ev.start?.date,
234	        seriesId,
235	      };
236	      // Notify only for a genuinely new, not-yet-handled occurrence of a series we
237	      // weren't already tracking — one alert per recurring series, not per
238	      // instance, and never for an event a full re-scan merely re-discovered.
239	      const newInstance = !prevMarked[ev.id] && !handled[ev.id];
240	      if (newInstance && !knownSeries.has(seriesId) && !notifiedSeries.has(seriesId)) {
241	        newMarked.push(summary);
242	        notifiedSeries.add(seriesId);
243	      }
244	      marked[ev.id] = summary;
245	    } else {
246	      // Cancelled (deleted) or no longer a tracked visitor event (magic removed, or
247	      // not organized by us) → not pending. Report it so any optimistic in-page nudge
