265	  }
266	
267	  // Prune stale "handled" records so the overlay can't grow without bound.
268	  const handledCutoff = Date.now() - HANDLED_TTL_MS;
269	  for (const id of Object.keys(handled)) {
270	    if (handled[id] < handledCutoff) delete handled[id];
271	  }
