319	    const existing = bySeries.get(key);
320	    if (!existing || (m.start ?? '~').localeCompare(existing.start ?? '~') < 0) {
321	      bySeries.set(key, m);
322	    }
323	  }
324	  return [...bySeries.values()].sort((a, b) =>
325	    (a.start ?? '').localeCompare(b.start ?? ''),
326	  );
327	}
