345	    !b || (a.start ?? '~').localeCompare(b.start ?? '~') < 0;
346	
347	  const bySeries = new Map<
348	    string,
349	    { soonestAny: VisitorEventSummary; soonestPending?: VisitorEventSummary }
350	  >();
351	  for (const m of Object.values(marked)) {
352	    const key = m.seriesId ?? m.eventId;
353	    const entry = bySeries.get(key) ?? { soonestAny: m };
354	    if (earlier(m, entry.soonestAny)) entry.soonestAny = m;
355	    if (!isSent(m) && earlier(m, entry.soonestPending)) entry.soonestPending = m;
356	    bySeries.set(key, entry);
357	  }
