359	  const rows: PanelVisitorEvent[] = [...bySeries.values()].map((e) =>
360	    e.soonestPending
361	      ? { ...e.soonestPending, status: 'pending' }
362	      : { ...e.soonestAny, status: 'sent' },
363	  );
364	  return rows.sort((a, b) => (a.start ?? '').localeCompare(b.start ?? ''));
365	}
366	
367	/** Is this event id currently a known visitor event? */
368	export async function isEventMarked(eventId: string): Promise<boolean> {
369	  const marked = await readMarked();
370	  return !!marked[eventId];
371	}
