1	/**
2	 * Auth (background only). Mints a Google id_token (engine auth) + access_token
3	 * (Calendar read) via chrome.identity.launchWebAuthFlow against a Web OAuth
4	 * client, caches them in storage.session, and silently re-mints on expiry.
5	 *
6	 * The id_token's audience must be on the engine's AUXILIO_WORKSPACE_OAUTH_CLIENT_ID
7	 * allow-list. Calendar-only scopes (no Gmail/Drive — CASA line).
8	 */
9	import { OAUTH_CLIENT_ID } from './config';
10	import { engine } from './engine';
11	import type { AuthStatus } from './types';
12	
13	const SCOPES = [
14	  'openid',
15	  'email',
16	  'profile',
17	  'https://www.googleapis.com/auth/calendar.events.readonly',
18	  // Resolve guest names + photos the Calendar event API omits for external guests
19	  // (People API, client-side — mirrors the add-on). Both are *sensitive* scopes,
20	  // NOT restricted → no CASA, and still no Gmail/Drive. Adding these requires each
21	  // user to re-consent once (a silent renew won't widen scope).
22	  'https://www.googleapis.com/auth/contacts.readonly',
23	  'https://www.googleapis.com/auth/contacts.other.readonly',
24	].join(' ');
25	
26	const KEY = 'auxilio.tokens';
27	
28	/** Durable (storage.local) marker that the user has connected and intends to stay
29	 *  connected. Token bundles live in storage.session and are WIPED on every browser
30	 *  restart, so an absent bundle can't tell "never signed in" from "session cleared,
31	 *  silent renew due." This flag survives restarts: while it's set, a failed silent
32	 *  renew means auth has lapsed (surface a reconnect), not that the user is signed
33	 *  out. Cleared only on explicit sign-out. */
34	const CONNECTED_KEY = 'auxilio.connected';
35	/** Durable copy of the connected account's email. storage.session (the token
36	 *  bundle) is wiped on browser restart, but a silent renew needs to know WHICH
37	 *  Google account to refresh — without a login_hint, prompt=none fails on a
38	 *  multi-account profile (Google can't pick one non-interactively), which surfaces
39	 *  as every write silently failing. Survives the restart so the hint is available. */
40	const EMAIL_KEY = 'auxilio.email';
41	
42	interface TokenBundle {
43	  idToken: string;
44	  accessToken: string;
45	  email?: string;
46	  expiresAt: number;
47	}
48	
49	function parseFragment(redirectUrl: string) {
50	  const params = new URLSearchParams(new URL(redirectUrl).hash.slice(1));
51	  return {
52	    accessToken: params.get('access_token') ?? '',
53	    idToken: params.get('id_token') ?? '',
54	    code: params.get('code') ?? '',
55	    expiresIn: Number(params.get('expires_in') ?? '3600'),
56	    error: params.get('error') ?? undefined,
57	  };
58	}
59	
60	function emailFromIdToken(idToken: string): string | undefined {
