1	import { useEffect, useRef, useState } from 'react';
2	import { useQueryClient } from '@tanstack/react-query';
3	import {
4	  AlertCircle,
5	  ArrowLeft,
6	  CheckCircle2,
7	  Clock,
8	  DoorOpen,
9	  ExternalLink,
10	  Eye,
11	  LogIn,
12	  RefreshCw,
13	} from 'lucide-react';
14	import {
15	  Button,
16	  Card,
17	  IconButton,
18	  Logo,
19	  SelectField,
20	  Skeleton,
21	} from '@/design/components';
22	import {
23	  ACTIVE_EID_KEY,
24	  ACTIVE_SNAPSHOT_KEY,
25	  REFRESH_ACTIVE,
26	  RpcError,
27	  rpc,
28	} from '@/lib/messaging';
29	import { MAGIC_ADDRESS } from '@/lib/config';
30	import type { PreviewResponse } from '@/lib/types';
31	import {
32	  useActiveEid,
33	  useActiveSnapshot,
34	  useAuthStatus,
35	  useDraft,
36	  usePatchDraft,
37	  usePreview,
38	  useResolveEvent,
39	  useResolveGuestNames,
40	  useSend,
41	  useSignIn,
42	  useVisitorEvents,
43	} from './hooks';
44	import { AccountMenu } from './AccountMenu';
45	import { EmptyState } from './EmptyState';
46	import { RosterRow } from './RosterRow';
47	import { PreviewSheet } from './PreviewSheet';
48	import { SignInGate } from './SignInGate';
49	
50	const isAuthError = (err: unknown) => err instanceof RpcError && !!err.needsAuth;
51	
52	export function VisitPanel() {
53	  // `storedEid` is what the content script is pointing us at (auto-follow). We
54	  // freeze the *displayed* `eid` while busy so following never switches the view
55	  // mid-action (Guard 1); edits already persist on blur (Guard 2).
56	  const storedEid = useActiveEid();
57	  const snapshot = useActiveSnapshot();
58	  const [eid, setEid] = useState<string | null>(storedEid);
59	  const auth = useAuthStatus();
60	  // Picker fuels the "open from list" empty state (and graceful fallback).
61	  const visitorEvents = useVisitorEvents(!eid && !!auth.data?.signedIn);
62	  const resolve = useResolveEvent(eid);
63	  const event = resolve.data;
64	  // Host-only: only the event's ORGANIZER registers visitors. A guest who opens the
65	  // panel for an event they were merely invited to must not be able to edit/send —
66	  // their copy of the event carries the magic address too, but it isn't theirs to
67	  // manage. We compare the resolved organizer to the signed-in user; on any missing
68	  // signal we default to NOT a guest, so a legitimate host is never blocked.
69	  const myEmail = auth.data?.email?.toLowerCase();
70	  const organizerEmail = event?.organizerEmail?.toLowerCase();
71	  const isGuest = !!event && !!organizerEmail && !!myEmail && organizerEmail !== myEmail;
72	  const draft = useDraft(event, !isGuest);
73	  // Fill real names + photos for email-only guests in the background (People API).
74	  useResolveGuestNames(draft.data);
75	
76	  const patch = usePatchDraft(event?.iCalUid);
77	  const send = useSend(event?.iCalUid, event?.start, event?.end);
78	  const preview = usePreview(event?.iCalUid);
79	  const signIn = useSignIn();
80	
81	  // While a write is in flight, ignore the post-save REFRESH_ACTIVE refetch: a
82	  // DRAFT_LOAD that reads the engine before our PATCH commits would overwrite the
83	  // host's just-made edit (the "edit reverts" report). The mutation's own onSuccess
84	  // reconciles the draft when it settles. Ref so the listener reads the live value.
85	  const mutatingRef = useRef(false);
86	  mutatingRef.current = patch.isPending || send.isPending;
87	
88	  const [previewData, setPreviewData] = useState<{
89	    preview: PreviewResponse;
90	    recipient: string;
91	  } | null>(null);
92	  // Non-structural host edits (name/phone change, template switch) leave no roster
93	  // delta, so we track them against a BASELINE captured lazily — the first time the
94	  // host touches a given guest (or the template), we snapshot its pre-edit value.
95	  // Deriving "edited" as a diff against that baseline means a revert back to the
96	  // original clears it (button deactivates), and a background name resolution that
97	  // fills an UNtouched guest is never mistaken for an edit (it's not in the baseline).
98	  // Refs (not state) so capturing doesn't itself trigger a render; the patch that
99	  // follows re-renders and recomputes the diff. Cleared when the event changes or a
100	  // send succeeds (the draft then reflects reality).
101	  const editBaseline = useRef<Record<string, { name: string; phone: string }>>({});
102	  const templateBaseline = useRef<string | undefined>(undefined);
103	  const resetEditBaseline = () => {
104	    editBaseline.current = {};
105	    templateBaseline.current = undefined;
106	  };
107	  useEffect(resetEditBaseline, [event?.iCalUid]);
108	
109	  // Guard 1: hold the current event while sending / previewing; catch up once idle.
110	  const busy = send.isPending || preview.isPending || !!previewData;
111	  useEffect(() => {
112	    if (!busy) setEid(storedEid);
113	  }, [storedEid, busy]);
114	
115	  // Post-save refresh: the background sync poll broadcasts when the active event
116	  // changed on the server (no DOM); refetch so the roster reflects saved state.
117	  const qc = useQueryClient();
118	  useEffect(() => {
119	    const listener = (msg: { type?: string }) => {
120	      if (msg?.type === REFRESH_ACTIVE) {
121	        // Don't clobber an in-flight edit (see mutatingRef).
122	        if (mutatingRef.current) return;
123	        qc.invalidateQueries({ queryKey: ['resolve'] });
124	        qc.invalidateQueries({ queryKey: ['draft'] });
125	      }
126	    };
127	    chrome.runtime.onMessage.addListener(listener);
128	    return () => chrome.runtime.onMessage.removeListener(listener);
129	  }, [qc]);
130	
131	  // Back → clear the active event/snapshot, returning to the home list.
132	  const clearActive = () =>
133	    chrome.storage.session.remove([ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY]);
134	  // Show Back in every screen except the pure home (no event, no snapshot).
135	  const back = eid || snapshot?.magicPresent ? clearActive : undefined;
136	
137	  // ---- gating states ----
138	  if (!eid) {
139	    // New, not-yet-saved visitor event (no eid, but the DOM saw the magic
140	    // address) → preview the detected guests + prompt to save.
141	    if (snapshot?.magicPresent) {
142	      return (
143	        <Shell onBack={back}>
144	          <NoticeState
145	            title="Save the event to issue passes"
146	            body="This event isn’t saved yet, so passes can’t be issued. Add your guests and save it in Google Calendar, then reopen Manage Visitors."
147	            guests={snapshot.guestEmails}
148	          />
149	        </Shell>
150	      );
151	    }
152	    return (
153	      <Shell>
154	        <EmptyState
155	          auth={auth.data}
156	          events={visitorEvents.data}
157	          loading={visitorEvents.isLoading}
158	          onPick={(ev) => {
159	            // Just point the panel at the picked event — no tab navigation. Use
160	            // "Open in Calendar" in the summary to jump to it explicitly.
161	            chrome.storage.session.set({ [ACTIVE_EID_KEY]: ev.eid });
162	          }}
163	        />
164	      </Shell>
165	    );
166	  }
167	  if (isAuthError(resolve.error) || isAuthError(draft.error)) {
168	    return <Shell onBack={back}><SignInGate /></Shell>;
169	  }
170	  if (resolve.isLoading) return <Shell onBack={back}><LoadingState label="Reading event…" /></Shell>;
171	  if (resolve.isError) {
172	    const msg = (resolve.error as Error).message;
173	    if (msg === 'NOT_SAVED') {
174	      return (
175	        <Shell onBack={back}>
176	          <NoticeState
177	            title="Save the event to issue passes"
178	            body="This event isn’t saved yet, so passes can’t be issued. Save it in Google Calendar, then reopen Manage Visitors."
179	            onRetry={() => resolve.refetch()}
180	            guests={snapshot?.guestEmails}
181	          />
182	        </Shell>
183	      );
184	    }
185	    return (
186	      <Shell onBack={back}>
187	        <ErrorState message={msg} onRetry={() => resolve.refetch()} />
188	      </Shell>
189	    );
190	  }
191	  // Guest of someone else's event → nothing to manage here (see isGuest above).
192	  if (isGuest) {
193	    return (
194	      <Shell onBack={back}>
195	        <NoticeState
196	          title="You are a guest of this event"
197	          body={`${hostNameFromEmail(event?.organizerEmail)} manages visitor passes for this event. There is nothing for you to do here.`}
198	        />
199	      </Shell>
200	    );
201	  }
202	  // Event resolved but no iCalUID → the draft query can't run (would sit on a
203	  // skeleton forever). Surface it instead of hanging.
204	  if (event && !event.iCalUid) {
205	    return (
206	      <Shell onBack={back}>
207	        <NoticeState
208	          title="Can’t register from this event"
209	          body="This event has no calendar UID yet. This usually means it is not fully saved. Save it in Google Calendar and try again."
210	          onRetry={() => resolve.refetch()}
211	        />
212	      </Shell>
213	    );
214	  }
215	  if (draft.isError) {
216	    return (
217	      <Shell onBack={back}>
218	        <ErrorState message={(draft.error as Error).message} onRetry={() => draft.refetch()} />
219	      </Shell>
220	    );
221	  }
222	  if (!draft.data) {
223	    return <Shell onBack={back}><RosterSkeleton title={event?.title} /></Shell>;
224	  }
225	
226	  // Defense in depth: the marker (magic) address must NEVER render as a guest. We
227	  // strip it on the way OUT to the engine (lib/calendar.ts) and the engine strips it
228	  // too, but a draft the engine persisted earlier — or one its conservative reconcile
229	  // preserves when the event has no other guests left (the "toggle the only internal
230	  // member off → magic reappears" report) — can still come back carrying it. Filter the
231	  // engine-returned roster here so it can't reach the panel regardless of that path.
232	  const data = {
233	    ...draft.data,
234	    roster: draft.data.roster.filter((g) => g.email.toLowerCase() !== MAGIC_ADDRESS),
235	  };
236	  const included = data.roster.filter((g) => g.include);
237	  const sentCount = data.roster.filter((g) => g.status === 'sent').length;
238	
239	  const templates = data.emailTemplates;
240	  // One template for the whole event (engine stores per-guest; we set all guests
241	  // to the chosen key).
242	  const currentTemplate =
243	    data.roster.find((g) => g.emailTemplateKey)?.emailTemplateKey ??
244	    templates.find((t) => t.isDefault)?.key ??
245	    templates[0]?.key;
246	
247	  // What's actually pending. A new/uninvited guest still to get a pass, or a sent
248	  // guest toggled off (a pending revoke), is a STRUCTURAL change visible in the
249	  // roster (and reverts cleanly because it's recomputed here every render).
250	  const pendingNew = data.roster.filter(
251	    (g) => g.include && g.status !== 'sent' && g.status !== 'cancelled',
252	  );
253	  const pendingCancel = data.roster.filter((g) => g.status === 'sent' && !g.include);
254	
255	  // Non-structural edits: guests whose name/phone now differs from their captured
256	  // baseline, or a template switched away from its baseline. Reverting to the
257	  // baseline value drops the guest back out, so the button deactivates.
258	  const editedGuests = data.roster.filter((g) => {
259	    const b = editBaseline.current[g.email];
260	    return !!b && ((g.name ?? '') !== b.name || (g.phone ?? '') !== b.phone);
261	  });
262	  const templateChanged =
263	    templateBaseline.current !== undefined && currentTemplate !== templateBaseline.current;
264	  const edited = editedGuests.length > 0 || templateChanged;
265	
266	  const hasChanges = pendingNew.length > 0 || pendingCancel.length > 0 || edited;
267	
268	  // How many passes this send will actually change. A FIRST send issues a pass to
269	  // every included guest, so the count is the whole included list. An UPDATE to an
270	  // already-issued event only touches what the host changed — newly added guests,
271	  // pending cancels, and the specific guests whose name/phone was edited — so editing
272	  // one guest among five reports one, not five. (A template switch re-renders every
273	  // included guest's email, so it counts as all of them.)
274	  const changeCount = !data.materialized
275	    ? included.length
276	    : templateChanged
277	      ? included.length
278	      : pendingNew.length + pendingCancel.length + editedGuests.length;
279	  // Already-issued event with literally nothing to do → no point re-sending.
280	  const nothingToDo = data.materialized && !hasChanges;
281	
282	  const patchGuest = (email: string, edit: Record<string, unknown>) => {
283	    // An include toggle is STRUCTURAL (pendingNew/pendingCancel) — no baseline needed.
284	    // For a name/phone edit, snapshot this guest's PRE-edit values the first time it's
285	    // touched, so a later revert (or a background name fill on an untouched guest)
286	    // diffs correctly.
287	    if ('name' in edit || 'phone' in edit) {
288	      if (!(email in editBaseline.current)) {
289	        const g = data.roster.find((x) => x.email === email);
290	        if (g) editBaseline.current[email] = { name: g.name ?? '', phone: g.phone ?? '' };
291	      }
292	    }
293	    patch.mutate({ guests: [{ email, ...edit }] });
294	  };
295	
296	  const setEventTemplate = (key: string) => {
297	    // Snapshot the effective template before the first switch, so picking the
298	    // original template back clears the diff.
299	    if (templateBaseline.current === undefined) templateBaseline.current = currentTemplate;
300	    patch.mutate({ guests: data.roster.map((g) => ({ email: g.email, emailTemplateKey: key })) });
301	  };
302	
303	  // Review & send: render the real email for a representative included guest,
304	  // then Send/Cancel from the preview.
305	  const reviewEmail = included[0]?.email;
306	  const openReview = () => {
307	    if (!reviewEmail) return;
308	    preview.mutate(reviewEmail, {
309	      onSuccess: (d) => setPreviewData({ preview: d, recipient: reviewEmail }),
310	    });
311	  };
312	
313	  // First send needs at least one included guest; an already-issued event needs a
314	  // real pending change — otherwise the button is irrelevant and stays disabled.
315	  const canSend =
316	    !send.isPending && (data.materialized ? hasChanges : included.length > 0);
317	  const reviewLabel = data.materialized ? 'Review & update passes' : 'Review & send passes';
318	  // A write (edit or send) failed because the session lapsed. Surface it instead of
319	  // letting the change silently revert — the host signs in again and re-sends.
320	  const writeAuthError = isAuthError(patch.error) || isAuthError(send.error);
321	
322	  return (
323	    <Shell onBack={back}>
324	      <div className="enter" style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
325	        {/* Event summary */}
326	        <Card style={{ display: 'grid', gap: 'var(--space-sm)' }}>
327	          <div className="type-title-lg">{event?.title || 'Untitled event'}</div>
328	          {event?.start && (
329	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
330	              <Clock size={15} strokeWidth={2} />
331	              {formatWhen(event.start, event.end)}
332	            </div>
333	          )}
334	          {event?.rooms && event.rooms.length > 0 && (
335	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
336	              <DoorOpen size={15} strokeWidth={2} />
337	              <span className="row__ellipsis">{event.rooms.join(', ')}</span>
338	            </div>
339	          )}
340	          {event?.description && (
341	            <div
342	              className="type-label-sm text-muted"
343	              style={{
344	                whiteSpace: 'pre-wrap',
345	                maxHeight: 72,
346	                overflow: 'hidden',
347	                borderTop: '1px solid var(--color-outline-variant)',
348	                paddingTop: 'var(--space-sm)',
349	              }}
350	            >
351	              {event.description}
352	            </div>
353	          )}
354	          {eid && (
355	            <Button
356	              variant="text"
357	              icon={<ExternalLink size={16} strokeWidth={2} />}
358	              onClick={() => void rpc({ type: 'NAVIGATE_TO_EVENT', eid })}
359	              // Negative left margin = the text button's own horizontal padding,
360	              // so the label optically aligns to the card edge while the hit area
361	              // and hover state layer stay intact (MD3 text-button placement).
362	              style={{ justifySelf: 'start', marginLeft: 'calc(-1 * var(--space-md))' }}
363	            >
364	              Open in Calendar
365	            </Button>
366	          )}
367	          {templates.length >= 2 && (
368	            <SelectField
369	              label="Email template (all guests)"
370	              value={currentTemplate}
371	              onChange={(e) => setEventTemplate(e.target.value)}
372	            >
373	              {templates.map((t) => (
374	                <option key={t.key} value={t.key}>
375	                  {t.name}
376	                  {t.isDefault ? ' (default)' : ''}
377	                </option>
378	              ))}
379	            </SelectField>
380	          )}
381	        </Card>
382	
383	        {/* Roster */}
384	        <section>
385	          <div
386	            className="type-label-sm text-muted"
387	            style={{ textTransform: 'uppercase', marginBottom: 4 }}
388	          >
389	            Guests · {included.length} getting a pass
390	          </div>
391	          {data.roster.length === 0 ? (
392	            <Card className="type-body text-muted">
393	              No guests on this event yet. Add attendees in Calendar, then reopen.
394	            </Card>
395	          ) : (
396	            <div className="roster">
397	              {data.roster.map((g) => (
398	                <RosterRow
399	                  key={g.email}
400	                  guest={g}
401	                  onChange={(edit) => patchGuest(g.email, edit)}
402	                />
403	              ))}
404	            </div>
405	          )}
406	        </section>
407	
408	        {/* Send result */}
409	        {send.isSuccess && <SendSummary result={send.data} />}
410	        {send.isError && !isAuthError(send.error) && (
411	          <div className="banner banner--error" role="alert">
412	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
413	            <span className="type-body">{(send.error as Error).message}</span>
414	          </div>
415	        )}
416	      </div>
417	
418	      {/* Sticky action bar */}
419	      <footer
420	        style={{
421	          padding: 'var(--space-md) var(--space-lg)',
422	          borderTop: '1px solid var(--color-outline-variant)',
423	          background: 'var(--color-surface-lowest)',
424	        }}
425	      >
426	        <AutoHideBanner show={nothingToDo}>
427	          <div
428	            className="banner banner--info"
429	            role="status"
430	            style={{ marginBottom: 'var(--space-sm)' }}
431	          >
432	            <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
433	            <span className="type-body">Up to date. No changes to send.</span>
434	          </div>
435	        </AutoHideBanner>
436	        {writeAuthError && (
437	          <div
438	            className="banner banner--error"
439	            role="alert"
440	            style={{ marginBottom: 'var(--space-sm)', flexWrap: 'wrap' }}
441	          >
442	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
443	            <span className="type-body" style={{ flex: 1, minWidth: 180 }}>
444	              Your session expired. Sign in again to save your changes.
445	            </span>
446	            <Button
447	              variant="tonal"
448	              loading={signIn.isPending}
449	              icon={<LogIn size={16} strokeWidth={2} />}
450	              onClick={() => signIn.mutate()}
451	            >
452	              Sign in
453	            </Button>
454	          </div>
455	        )}
456	        <Button
457	          block
458	          loading={preview.isPending}
459	          disabled={!canSend}
460	          icon={<Eye size={18} strokeWidth={2} />}
461	          onClick={openReview}
462	        >
463	          {preview.isPending
464	            ? 'Loading preview…'
465	            : `${reviewLabel}${changeCount ? ` (${changeCount})` : ''}`}
466	        </Button>
