469	            {(preview.error as Error).message}
470	          </div>
471	        )}
472	        {sentCount > 0 && !send.isPending && !nothingToDo && (
473	          <div className="type-label-sm text-muted" style={{ textAlign: 'center', marginTop: 6 }}>
474	            {sentCount} pass{sentCount > 1 ? 'es' : ''} already issued
475	          </div>
476	        )}
477	      </footer>
478	
479	      {previewData && (
480	        <PreviewSheet
481	          preview={previewData.preview}
482	          recipient={previewData.recipient}
483	          totalCount={changeCount}
484	          update={data.materialized}
485	          sending={send.isPending}
486	          onSend={() =>
