503	/** Shows its children for ~5s each time `show` flips true, then auto-hides — an
504	 *  ephemeral notice rather than a banner that lingers. Re-shows if `show` cycles. */
505	function AutoHideBanner({ show, children }: { show: boolean; children: React.ReactNode }) {
506	  const [visible, setVisible] = useState(false);
507	  useEffect(() => {
508	    if (!show) {
509	      setVisible(false);
510	      return;
511	    }
512	    setVisible(true);
513	    const t = setTimeout(() => setVisible(false), 5000);
514	    return () => clearTimeout(t);
515	  }, [show]);
516	  return visible ? <>{children}</> : null;
517	}
