579	            <Skeleton width={44} height={24} radius={999} />
580	            <div style={{ flex: 1, display: 'grid', gap: 6 }}>
581	              <Skeleton width="50%" />
582	              <Skeleton width="70%" height={12} />
583	            </div>
584	          </div>
585	        ))}
586	      </Card>
587	    </div>
