603	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-md)' }}>
604	      <Card style={{ display: 'grid', gap: 'var(--space-sm)', padding: 'var(--space-xl)' }}>
605	        <span className="type-title-lg">{title}</span>
