619	        <Card style={{ display: 'grid', gap: 'var(--space-xs)' }}>
620	          <span className="type-label-sm text-muted" style={{ textTransform: 'uppercase' }}>
621	            Guests detected on this event
622	          </span>
623	          {guests.map((g) => (
624	            <span key={g} className="type-body row__ellipsis">{g}</span>
625	          ))}
