631	
632	function ErrorState({ message, onRetry }: { message: string; onRetry: () => void }) {
633	  return (
634	    <div style={{ padding: 'var(--space-lg)' }}>
635	      <div className="banner banner--error" role="alert" style={{ marginBottom: 'var(--space-md)' }}>
636	        <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
637	        <span className="type-body">{message}</span>
