646	function SendSummary({
647	  result,
648	}: {
649	  result: import('@/lib/types').SendResponse;
650	}) {
651	  return (
652	    <div
653	      className="banner"
654	      role="status"
655	      aria-live="polite"
656	      style={{ background: 'var(--color-success-container)', color: 'var(--color-on-success-container)' }}
657	    >
658	      <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
659	      <div>
660	        <div className="type-label">
661	          {(() => {
662	            const updatedCount = result.updated?.length ?? 0;
663	            if (result.created.length > 0)
664	              return `${result.created.length} pass${result.created.length > 1 ? 'es' : ''} sent`;
665	            if (updatedCount > 0)
666	              return `${updatedCount} pass${updatedCount > 1 ? 'es' : ''} updated`;
667	            if (result.cancelled.length > 0) return 'Passes updated';
668	            return 'No changes';
669	          })()}
670	          {result.cancelled.length > 0 && ` · ${result.cancelled.length} cancelled`}
671	        </div>
672	        {result.failed.length > 0 && (
673	          <ul className="type-label-sm" style={{ margin: '4px 0 0', paddingLeft: 16 }}>
674	            {result.failed.map((f) => (
675	              <li key={f.visitorEmail}>
676	                {f.visitorEmail}: {f.reason}
677	              </li>
678	            ))}
679	          </ul>
680	        )}
681	      </div>
682	    </div>
683	  );
684	}
685	
686	/** Friendly host name from the organizer email (local part, title-cased), for the
687	 *  guest notice. Falls back to "The host" when there's no usable email. */
688	function hostNameFromEmail(email?: string): string {
689	  const local = (email ?? '').split('@')[0] ?? '';
690	  const name = local
691	    .replace(/[._-]+/g, ' ')
692	    .replace(/\b\w/g, (c) => c.toUpperCase())
693	    .trim();
694	  return name || 'The host';
695	}
696	
697	function formatWhen(start: string, end?: string): string {
698	  const allDay = !start.includes('T');
699	  const s = new Date(start);
700	  const date = s.toLocaleDateString(undefined, { weekday: 'short', day: 'numeric', month: 'short' });
701	  if (allDay) return `${date} · All day`;
702	  const t = (d: Date) => d.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
703	  return end ? `${date} · ${t(s)} to ${t(new Date(end))}` : `${date} · ${t(s)}`;
704	}
