503	export async function handleVisitorRequest(
504	  req: IncomingMessage,
505	  res: ServerResponse,
506	): Promise<boolean> {
507	  const { pathname, query } = parseUrl(req.url ?? '', true);
508	  const method = req.method?.toUpperCase() ?? 'GET';
509	
510	  if (!pathname) return false;
511	
512	  if (method === 'OPTIONS') {
513	    corsPreflight(res);
514	    return true;
515	  }
516	
517	  // ── Visitor phone OTP (dormant; gated by VISITOR_OTP_ENABLED) ──
518	  // Wired but not used by the registration flow. Flip the env flag and
519	  // call from WalkInRegisterPage once an SMS provider is configured.
520	
521	  if (pathname === '/api/visitor/otp/request' && method === 'POST') {
522	    const { isVisitorOtpEnabled, sendVisitorOtp } = await import('./visitor-otp');
523	    if (!isVisitorOtpEnabled()) {
524	      json(res, 501, { error: 'Visitor OTP is not enabled.' });
525	      return true;
526	    }
527	    const body = await readBodyJson(req);
528	    const phone = validateVisitorPhone(normalizeBodyString(body.phone));
529	    if (!phone) {
530	      json(res, 400, { error: 'Valid phone number required.' });
531	      return true;
532	    }
533	    const result = await sendVisitorOtp(phone);
534	    if (!result.sent) {
535	      json(res, 500, { error: result.error ?? 'Failed to send OTP.' });
536	      return true;
537	    }
538	    json(res, 200, { ok: true });
539	    return true;
540	  }
541	
542	  if (pathname === '/api/visitor/otp/verify' && method === 'POST') {
543	    const { isVisitorOtpEnabled, verifyVisitorOtp } = await import('./visitor-otp');
544	    if (!isVisitorOtpEnabled()) {
545	      json(res, 501, { error: 'Visitor OTP is not enabled.' });
546	      return true;
547	    }
548	    const body = await readBodyJson(req);
549	    const phone = validateVisitorPhone(normalizeBodyString(body.phone));
550	    const code = normalizeBodyString(body.otp ?? body.code);
551	    if (!phone || !code) {
552	      json(res, 400, { error: 'Phone and OTP code are required.' });
553	      return true;
554	    }
555	    const result = verifyVisitorOtp(phone, code);
556	    if (!result.ok) {
557	      json(res, 400, { error: result.error });
558	      return true;
559	    }
560	    json(res, 200, { ok: true });
561	    return true;
562	  }
563	
564	  // ── Calendar inbound (magic-address .ics ingestion) — DEPRECATED ───────
565	  // D5 (2026-06-17): the magic-address path is retired — we no longer ask hosts to
566	  // add a magic guest/room, nor parse inbound-email .ics. Pass creation is the
567	  // add-on (host curates + sends). This route is DORMANT by default; the parser +
568	  // spine support stay in place so it can be re-enabled with VISITOR_CALENDAR_INBOUND_ENABLED=1
569	  // if a zero-build path is ever needed again (e.g. an external tenant).
570	  if (pathname === '/api/visitor/calendar/inbound' && method === 'POST') {
571	    if (process.env.VISITOR_CALENDAR_INBOUND_ENABLED !== '1') {
572	      json(res, 410, { error: 'magic-address .ics ingestion is retired (use the calendar add-on)' });
573	      return true;
574	    }
575	    const secret = process.env.VISITOR_CALENDAR_INBOUND_SECRET;
576	    if (secret) {
577	      const provided = (req.headers['x-calendar-secret'] as string | undefined)
578	        ?? (query.secret as string | undefined);
579	      if (provided !== secret) {
580	        json(res, 401, { error: 'unauthorized' });
581	        return true;
582	      }
583	    }
584	
585	    const raw = await readBody(req);
586	    // Body may be: raw .ics, a raw email containing an .ics, or JSON from a
587	    // provider webhook with the email/attachment under a known field.
588	    let icsText: string | null = extractIcsFromEmail(raw) ?? (/(BEGIN:VCALENDAR)/i.test(raw) ? raw : null);
589	    if (!icsText && raw.trim().startsWith('{')) {
590	      try {
591	        const payload = JSON.parse(raw) as Record<string, unknown>;
592	        const candidate = [payload.ics, payload.body, payload.text, payload['raw'], payload['RawEmail'], payload['email']]
593	          .find((v): v is string => typeof v === 'string');
594	        if (candidate) icsText = extractIcsFromEmail(candidate) ?? candidate;
595	      } catch { /* not JSON, ignore */ }
596	    }
597	
598	    if (!icsText) {
599	      json(res, 422, { error: 'no calendar invite (.ics) found in payload' });
600	      return true;
601	    }
602	
603	    const event = parseIcs(icsText);
604	    if (!event) {
605	      json(res, 422, { error: 'could not parse a VEVENT with a UID' });
606	      return true;
607	    }
608	
609	    try {
610	      const result = await ingestCalendarEvent(event);
611	      json(res, 200, result);
612	    } catch (err) {
613	      console.error('[Calendar] inbound ingest failed:', err);
614	      json(res, 500, { error: 'ingest failed' });
615	    }
616	    return true;
617	  }
618	
619	  // ── Calendar push notifications (Google watch webhook) ────
620	  // Google POSTs here when a watched calendar changes. The body is irrelevant
621	  // (the headers carry the channel id + state). Ack 200 fast, then process.
622	  if (pathname === '/api/visitor/calendar/notifications' && method === 'POST') {
623	    await readBody(req).catch(() => '');
624	    res.writeHead(200);
625	    res.end();
626	    void handleCalendarNotification(req.headers).catch((err) => console.error('[CalendarWatch] notification handling failed:', err));
627	    return true;
628	  }
629	
630	  // ── Google Search Console site-verification file ──────────
631	  // Serves the google<code>.html file so the webhook domain can be verified
632	  // (required before Google will deliver push). Content comes from env.
633	  if (method === 'GET' && /^\/google[0-9a-z]+\.html$/i.test(pathname)) {
634	    const fileName = process.env.GOOGLE_SITE_VERIFICATION_FILE;
635	    const content = process.env.GOOGLE_SITE_VERIFICATION_CONTENT;
636	    if (fileName && content && pathname === `/${fileName}`) {
637	      res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
638	      res.end(content);
639	      return true;
640	    }
641	  }
642	
643	  // ── Calendar sync: manual trigger + diagnostics ───────────
644	  // Forces one poll pass instead of waiting for the interval. Returns how many
645	  // connections were processed; check server logs for per-event detail.
646	  if (pathname === '/api/visitor/calendar/sync-now' && (method === 'POST' || method === 'GET')) {
647	    const secret = process.env.VISITOR_CALENDAR_INBOUND_SECRET;
648	    if (secret) {
649	      const provided = (req.headers['x-calendar-secret'] as string | undefined) ?? (query.secret as string | undefined);
650	      if (provided !== secret) { json(res, 401, { error: 'unauthorized' }); return true; }
651	    }
652	    const connections = await listActiveOAuthConnections();
653	    const summary = connections.map((c) => ({ host: c.host_email, hasToken: !!c.refresh_token, syncToken: !!c.sync_token, status: c.status }));
654	    try {
655	      const result = await runCalendarSyncOnce();
656	      json(res, 200, { ok: true, ...result, connections: summary });
657	    } catch (err) {
658	      json(res, 500, { error: err instanceof Error ? err.message : 'sync failed', connections: summary });
659	    }
660	    return true;
661	  }
662	
663	  // ── Add-on email preview (HTML popup) ─────────────────────
664	  // Opened as a browser OVERLAY popup from the card (CardService OpenLink), which
665	  // cannot send the Bearer ID token — so this GET is authorized by a short-lived
666	  // HMAC-signed token instead. Returns the SAME branded HTML we'd actually send.
667	  if (pathname === '/api/visitor/calendar/addon/preview-html' && method === 'GET') {
668	    const payload = verifyPreviewToken(typeof query.t === 'string' ? query.t : undefined);
669	    if (!payload) {
670	      res.writeHead(401, { 'Content-Type': 'text/html; charset=utf-8' });
671	      res.end('<p style="font-family:sans-serif;padding:24px">Preview link expired. Reopen the card and try again.</p>');
672	      return true;
673	    }
674	    const iCalUid = String(payload.iCalUid ?? '');
675	    const visitorEmail = String(payload.visitorEmail ?? '').toLowerCase();
676	    const draft = iCalUid ? await getDraft(iCalUid) : null;
677	    const guest = draft?.roster.find((g) => g.email.toLowerCase() === visitorEmail);
678	    if (!draft || !guest) {
679	      res.writeHead(404, { 'Content-Type': 'text/html; charset=utf-8' });
680	      res.end('<p style="font-family:sans-serif;padding:24px">This guest is no longer in the draft.</p>');
681	      return true;
682	    }
683	    try {
684	      const data: PassEmailData = {
685	        visitorName: guest.name || visitorEmail,
686	        hostName: String(payload.hostName ?? ''),
687	        purpose: draft.title,
688	        validFrom: draft.eventStart,
689	        validUntil: draft.eventEnd,
690	        passUrl: 'https://preview.example/pass/preview',
691	        emailTemplateKey: guest.emailTemplateKey,
692	      };
693	      const rendered = await renderPassEmailPreview(data);
694	      // Wrap the email HTML in a minimal chrome so the popup reads as a preview.
695	      const banner = `<div style="font-family:sans-serif;background:#f1f3f4;color:#5f6368;padding:8px 16px;font-size:13px;border-bottom:1px solid #dadce0">Preview · Subject: ${escapeHtml(rendered.subject)} · To: ${escapeHtml(visitorEmail)}</div>`;
696	      res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
697	      res.end(banner + rendered.html);
698	    } catch (err) {
699	      console.error('[Addon] preview-html failed:', err);
700	      res.writeHead(500, { 'Content-Type': 'text/html; charset=utf-8' });
701	      res.end('<p style="font-family:sans-serif;padding:24px">Could not render the preview.</p>');
702	    }
703	    return true;
704	  }
705	
706	  // ── Auxilio Workspace add-on (calendar visitor add-on) ────
707	  // Card-action endpoints. Authenticated by the add-on's Google ID token (NOT an
708	  // admin session), and strictly additive — they reuse createVisitorInvite /
709	  // renderPassEmail / cancelInvitationById without touching the dashboard/Slack
710	  // routes. Spec: spec/2026-06-16_calendar_addon_register_endpoint.md.
711	  if (pathname.startsWith('/api/visitor/calendar/addon/')) {
712	    const identity = await verifyAddonIdToken(req.headers.authorization);
713	    if (!identity) {
714	      json(res, 401, { error: 'invalid or missing add-on identity token' });
715	      return true;
716	    }
717	    if (!isInternalHostEmail(identity.email)) {
718	      json(res, 403, { error: 'host domain not allowed' });
719	      return true;
720	    }
721	
722	    // POST /addon/draft — load (or lazily build + pre-fill) the Visit Draft.
723	    if (pathname === '/api/visitor/calendar/addon/draft' && method === 'POST') {
724	      const body = await readBodyJson(req);
725	      const iCalUid = String(body.iCalUid ?? '').trim();
726	      if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
727	      const attendees = Array.isArray(body.attendees)
728	        ? (body.attendees as { email: string; name?: string }[]).filter((a) => a && typeof a.email === 'string')
729	        : [];
730	      // Card-open path → trusted, complete attendee list → reconcile removals
731	      // (drop + cancel guests removed from the event). Plan §8B.
732	      const draft = await getOrCreateDraft({
733	        iCalUid,
734	        providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
735	        title: body.title ? String(body.title) : undefined,
736	        hostEmail: identity.email,
737	        attendees,
738	        eventStart: body.start ? String(body.start) : undefined,
739	        eventEnd: body.end ? String(body.end) : undefined,
740	        location: body.location ? String(body.location) : undefined,
741	      }, { reconcileRemovals: true });
742	
743	      // Gap A — link this event for background lifecycle (move/delete via the watch),
744	      // but only when X is the event ORGANIZER (don't attach lifecycle to meetings
745	      // X was merely invited to) and a pass actually exists for it. Keyed on the
746	      // real iCalUid so the watch's ingest finds it. Reuses the D8 link writer.
747	      const organizerEmail = body.organizerEmail ? String(body.organizerEmail).toLowerCase() : '';
748	      const isOrganizer = !!organizerEmail && organizerEmail === identity.email.toLowerCase();
749	      const sentIds = draft.roster.filter((g) => g.status === 'sent' && g.invitationId).map((g) => g.invitationId as string);
750	      if (isOrganizer && sentIds.length > 0) {
751	        await recordInvitationCalendarLink({
752	          iCalUid,
753	          providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
754	          organizerEmail: identity.email,
755	          invitationIds: sentIds,
756	          source: 'addon-link',
757	          eventStart: draft.eventStart ?? null,
758	          eventEnd: draft.eventEnd ?? null,
759	        }).catch((e) => console.warn('[Addon] event link failed:', e));
760	      }
761	
762	      // Gap C — tell the card whether background auto-sync (move/delete) is active.
763	      // Connected → seamless. Not connected → the card offers a one-tap Connect.
764	      const connected = await isCalendarConnected(identity.email).catch(() => false);
765	      const calendarSync = {
766	        connected,
767	        canConnect: isCalendarOAuthConfigured(),
768	        // Only meaningful to prompt when X owns the event (lifecycle attaches to it).
769	        relevant: isOrganizer,
770	        connectUrl: !connected && isCalendarOAuthConfigured()
771	          ? connectStartUrl({ email: identity.email })
772	          : undefined,
773	      };
774	
775	      // Host-safe email-template picker list (NOT the admin endpoint — a host has no
776	      // visitor.templates.view permission). Active email-channel templates only, with
777	      // the engine default flagged so the card can pre-select it. The card only shows
778	      // the dropdown when there's a real choice (≥2); one template → no clutter.
779	      const emailTemplates = await listAddonEmailTemplates();
780	
781	      json(res, 200, { ...draft, calendarSync, emailTemplates });
782	      return true;
783	    }
784	
785	    // POST /addon/status — read-only batch check: which of these events already
786	    // have at least one active (sent) pass. Lets a client (e.g. the Chrome
787	    // extension's background poll) suppress nudges for events already handled
788	    // through ANY surface (add-on, another device), not just locally. Unlike
789	    // /draft this is side-effect-free — no lazy draft creation, no link
790	    // recording — so it is cheap and safe to poll. Capped to bound the work.
791	    if (pathname === '/api/visitor/calendar/addon/status' && method === 'POST') {
792	      const body = await readBodyJson(req);
793	      const iCalUids = (Array.isArray(body.iCalUids) ? body.iCalUids : [])
794	        .map((v: unknown) => String(v ?? '').trim())
795	        .filter(Boolean)
796	        .slice(0, 100);
797	      const active: string[] = [];
798	      for (const uid of iCalUids) {
799	        const draft = await getDraft(uid);
800	        if (draft?.roster.some((g) => g.status === 'sent')) active.push(uid);
801	      }
802	      json(res, 200, { active });
803	      return true;
804	    }
805	
806	    // PATCH /addon/draft — persist a host edit (include toggle / name / phone / templates / location).
807	    if (pathname === '/api/visitor/calendar/addon/draft' && method === 'PATCH') {
808	      const body = await readBodyJson(req);
809	      const iCalUid = String(body.iCalUid ?? '').trim();
810	      if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
811	      const updated = await patchDraft(iCalUid, body.patch as DraftPatch | undefined);
812	      if (!updated) { json(res, 404, { error: 'draft not found' }); return true; }
813	      json(res, 200, updated);
814	      return true;
815	    }
816	
817	    // POST /addon/preview — render the invite email for one guest (no send).
818	    if (pathname === '/api/visitor/calendar/addon/preview' && method === 'POST') {
819	      const body = await readBodyJson(req);
820	      const iCalUid = String(body.iCalUid ?? '').trim();
821	      const visitorEmail = String(body.visitorEmail ?? '').trim().toLowerCase();
822	      const draft = iCalUid ? await getDraft(iCalUid) : null;
823	      const guest = draft?.roster.find((g) => g.email.toLowerCase() === visitorEmail);
824	      if (!draft || !guest) { json(res, 404, { error: 'guest not found in draft' }); return true; }
825	      try {
826	        const hostName = await resolveHostDisplayName(identity.email, identity.name);
827	        const data: PassEmailData = {
828	          visitorName: guest.name || visitorEmail,
829	          hostName,
830	          purpose: draft.title,
831	          validFrom: draft.eventStart,
832	          validUntil: draft.eventEnd,
833	          passUrl: 'https://preview.example/pass/preview',
834	          emailTemplateKey: guest.emailTemplateKey,
835	        };
836	        const rendered = await renderPassEmailPreview(data);
837	        // Signed token so the card can open the HTML popup without a Bearer. 30-min TTL:
838	        // the add-on now mints this at confirm-card BUILD time (not on the Preview click)
839	        // so the link can open directly and dodge the popup blocker — it must outlive the
840	        // host reading the confirm card. Expired → preview-html shows a "reopen" message.
841	        const previewToken = signPreviewToken({
842	          iCalUid,
843	          visitorEmail,
844	          hostName,
845	          exp: Date.now() + 30 * 60_000,
846	        });
847	        json(res, 200, { subject: rendered.subject, html: rendered.html, text: rendered.text, previewToken });
848	      } catch (err) {
849	        console.error('[Addon] preview failed:', err);
850	        json(res, 500, { error: 'Preview failed' });
851	      }
852	      return true;
853	    }
854	
855	    // POST /addon/send (and /addon/apply alias) — reconcile passes to the toggles:
856	    // create for newly-included guests, cancel for newly-excluded ones, keep the
857	    // rest. Used by both "Send passes" (Setup) and "Update passes" (Manage).
858	    if ((pathname === '/api/visitor/calendar/addon/send' || pathname === '/api/visitor/calendar/addon/apply') && method === 'POST') {
859	      const body = await readBodyJson(req);
860	      const iCalUid = String(body.iCalUid ?? '').trim();
861	      const draft = iCalUid ? await getDraft(iCalUid) : null;
862	      if (!draft) { json(res, 404, { error: 'draft not found' }); return true; }
863	      // Self-correct the event window from the times the card re-resolves at send.
864	      // The draft-open's time fetch (Calendar.Events.get) is flaky on a just-created
865	      // event, so the stored draft can lack start/end → applyDraft would fail every
866	      // guest with EVENT_TIME_MISSING. Trust fresh times when the card provides them.
867	      if (body.start) draft.eventStart = String(body.start);
868	      if (body.end) draft.eventEnd = String(body.end);
869	      const result = await applyDraft(draft, { hostName: identity.name });
870	      // Record the ledger from the active set; draft_authoritative so passive
871	      // producers reissue/cancel from the curated roster on move/delete.
872	      await recordDraftMaterialization({
873	        iCalUid,
874	        providerEventId: draft.providerEventId,
875	        organizerEmail: identity.email,
876	        invitationIds: result.invitationIds,
877	        eventStart: draft.eventStart ?? null,
878	        eventEnd: draft.eventEnd ?? null,
879	      });
880	      json(res, 200, {
881	        iCalUid,
882	        created: result.created,
883	        cancelled: result.cancelled,
884	        updated: result.updated,
885	        failed: result.failed,
886	        activeCount: result.invitationIds.length,
887	        draft: result.draft,
888	      });
889	      return true;
890	    }
891	
892	    // POST /addon/cancel-guest — cancel one guest's invite.
893	    if (pathname === '/api/visitor/calendar/addon/cancel-guest' && method === 'POST') {
894	      const body = await readBodyJson(req);
895	      const invitationId = String(body.invitationId ?? '').trim();
896	      if (!invitationId) { json(res, 422, { error: 'invitationId required' }); return true; }
897	      const cancelled = await cancelInvitationById(invitationId).catch(() => false);
898	      // Fire the cancellation notice (guest + host emails via the
899	      // visitor.invite_cancelled flow), same as every other cancel surface —
900	      // otherwise a per-guest cancel from the extension is silent. Scrub the id
901	      // from any calendar link/draft first so a later event move can't resurrect
902	      // it. Best-effort; never fail the cancel on a notify error.
903	      if (cancelled) {
904	        await unlinkInvitationFromCalendar(invitationId).catch((e) => console.warn('[Addon] cancel-guest unlink failed:', e));
905	        await markDraftGuestCancelledByInvitationId(invitationId).catch((e) => console.warn('[Addon] cancel-guest draft-mark failed:', e));
906	        await notifyInviteCancelled(invitationId, {
907	          cancelledBy: identity.name,
908	          reason: 'The host cancelled your visitor pass.',
909	        }).catch((e) => console.warn('[Addon] cancel-guest notify failed:', e));
910	      }
911	      json(res, 200, { invitationId, cancelled });
912	      return true;
913	    }
914	
915	    // POST /addon/connect-calendar — one-consent calendar connect from the Chrome
916	    // extension's hybrid sign-in. Exchanges the auth code for a refresh token so the
917	    // background poll keeps passes in sync when the panel is closed. Best-effort:
918	    // always 200 (sign-in must not fail on this); the connectUrl CTA is the fallback.
919	    if (pathname === '/api/visitor/calendar/addon/connect-calendar' && method === 'POST') {
920	      if (!isAuxilioExtensionOAuthConfigured()) {
921	        json(res, 200, { connected: false });
922	        return true;
923	      }
924	      const body = await readBodyJson(req);
925	      const code = String(body.code ?? '').trim();
926	      const redirectUri = String(body.redirectUri ?? '').trim();
927	      if (!code || !redirectUri) { json(res, 422, { error: 'code and redirectUri required' }); return true; }
928	
929	      // Never downgrade a host who already has offline access (e.g. Slack rw connect) —
930	      // any connected refresh token already powers the read poll. (D7)
931	      const existing = await getCalendarConnection(identity.email).catch(() => null);
932	      if (existing?.status === 'connected' && existing.refresh_token) {
933	        json(res, 200, { connected: true });
934	        return true;
935	      }
936	      try {
937	        const { refreshToken } = await exchangeExtensionCalendarCode(code, redirectUri);
938	        if (!refreshToken) { json(res, 200, { connected: false }); return true; }
939	        await upsertCalendarConnection({
940	          email: identity.email,
941	          refreshToken,
942	          scopeVersion: EXTENSION_SCOPE_VERSION,
943	        });
944	        // Register a push channel if webhooks are configured (no-op otherwise; poll covers it).
945	        void ensureWatchForHost(identity.email).catch((err) => console.warn('[Addon] watch register failed:', err));
946	        json(res, 200, { connected: true });
947	      } catch (err) {
948	        console.error('[Addon] connect-calendar failed:', err);
949	        json(res, 200, { connected: false });
950	      }
951	      return true;
952	    }
953	
954	    json(res, 404, { error: 'unknown add-on route' });
955	    return true;
956	  }
957	
958	  // ── Calendar OAuth connect: kick off the flow ─────────────
959	  // The Slack App Home / first-DM button points here with a signed `s` carrying
960	  // the host's email (+ slack id). We verify it, then 302 to Google consent with
961	  // login_hint pre-selecting the host's account.
962	  if (pathname === '/api/visitor/calendar/connect/start' && method === 'GET') {
963	    if (!isCalendarOAuthConfigured()) {
964	      json(res, 503, { error: 'Calendar OAuth is not configured.' });
965	      return true;
966	    }
967	    const stateParam = typeof query.s === 'string' ? query.s : undefined;
968	    const payload = verifyCalendarState(stateParam);
969	    if (!payload || !stateParam) {
970	      json(res, 400, { error: 'Invalid or expired connect link. Please reopen it from Slack.' });
971	      return true;
972	    }

