export async function handleVisitorRequest(
  req: IncomingMessage,
  res: ServerResponse,
): Promise<boolean> {
  const { pathname, query } = parseUrl(req.url ?? '', true);
  const method = req.method?.toUpperCase() ?? 'GET';

  if (!pathname) return false;

  if (method === 'OPTIONS') {
    corsPreflight(res);
    return true;
  }

  // ── Visitor phone OTP (dormant; gated by VISITOR_OTP_ENABLED) ──
  // Wired but not used by the registration flow. Flip the env flag and
  // call from WalkInRegisterPage once an SMS provider is configured.

  if (pathname === '/api/visitor/otp/request' && method === 'POST') {
    const { isVisitorOtpEnabled, sendVisitorOtp } = await import('./visitor-otp');
    if (!isVisitorOtpEnabled()) {
      json(res, 501, { error: 'Visitor OTP is not enabled.' });
      return true;
    }
    const body = await readBodyJson(req);
    const phone = validateVisitorPhone(normalizeBodyString(body.phone));
    if (!phone) {
      json(res, 400, { error: 'Valid phone number required.' });
      return true;
    }
    const result = await sendVisitorOtp(phone);
    if (!result.sent) {
      json(res, 500, { error: result.error ?? 'Failed to send OTP.' });
      return true;
    }
    json(res, 200, { ok: true });
    return true;
  }

  if (pathname === '/api/visitor/otp/verify' && method === 'POST') {
    const { isVisitorOtpEnabled, verifyVisitorOtp } = await import('./visitor-otp');
    if (!isVisitorOtpEnabled()) {
      json(res, 501, { error: 'Visitor OTP is not enabled.' });
      return true;
    }
    const body = await readBodyJson(req);
    const phone = validateVisitorPhone(normalizeBodyString(body.phone));
    const code = normalizeBodyString(body.otp ?? body.code);
    if (!phone || !code) {
      json(res, 400, { error: 'Phone and OTP code are required.' });
      return true;
    }
    const result = verifyVisitorOtp(phone, code);
    if (!result.ok) {
      json(res, 400, { error: result.error });
      return true;
    }
    json(res, 200, { ok: true });
    return true;
  }

  // ── Calendar inbound (magic-address .ics ingestion) — DEPRECATED ───────
  // D5 (2026-06-17): the magic-address path is retired — we no longer ask hosts to
  // add a magic guest/room, nor parse inbound-email .ics. Pass creation is the
  // add-on (host curates + sends). This route is DORMANT by default; the parser +
  // spine support stay in place so it can be re-enabled with VISITOR_CALENDAR_INBOUND_ENABLED=1
  // if a zero-build path is ever needed again (e.g. an external tenant).
  if (pathname === '/api/visitor/calendar/inbound' && method === 'POST') {
    if (process.env.VISITOR_CALENDAR_INBOUND_ENABLED !== '1') {
      json(res, 410, { error: 'magic-address .ics ingestion is retired (use the calendar add-on)' });
      return true;
    }
    const secret = process.env.VISITOR_CALENDAR_INBOUND_SECRET;
    if (secret) {
      const provided = (req.headers['x-calendar-secret'] as string | undefined)
        ?? (query.secret as string | undefined);
      if (provided !== secret) {
        json(res, 401, { error: 'unauthorized' });
        return true;
      }
    }

    const raw = await readBody(req);
    // Body may be: raw .ics, a raw email containing an .ics, or JSON from a
    // provider webhook with the email/attachment under a known field.
    let icsText: string | null = extractIcsFromEmail(raw) ?? (/(BEGIN:VCALENDAR)/i.test(raw) ? raw : null);
    if (!icsText && raw.trim().startsWith('{')) {
      try {
        const payload = JSON.parse(raw) as Record<string, unknown>;
        const candidate = [payload.ics, payload.body, payload.text, payload['raw'], payload['RawEmail'], payload['email']]
          .find((v): v is string => typeof v === 'string');
        if (candidate) icsText = extractIcsFromEmail(candidate) ?? candidate;
      } catch { /* not JSON, ignore */ }
    }

    if (!icsText) {
      json(res, 422, { error: 'no calendar invite (.ics) found in payload' });
      return true;
    }

    const event = parseIcs(icsText);
    if (!event) {
      json(res, 422, { error: 'could not parse a VEVENT with a UID' });
      return true;
    }

    try {
      const result = await ingestCalendarEvent(event);
      json(res, 200, result);
    } catch (err) {
      console.error('[Calendar] inbound ingest failed:', err);
      json(res, 500, { error: 'ingest failed' });
    }
    return true;
  }

  // ── Calendar push notifications (Google watch webhook) ────
  // Google POSTs here when a watched calendar changes. The body is irrelevant
  // (the headers carry the channel id + state). Ack 200 fast, then process.
  if (pathname === '/api/visitor/calendar/notifications' && method === 'POST') {
    await readBody(req).catch(() => '');
    res.writeHead(200);
    res.end();
    void handleCalendarNotification(req.headers).catch((err) => console.error('[CalendarWatch] notification handling failed:', err));
    return true;
  }

  // ── Google Search Console site-verification file ──────────
  // Serves the google<code>.html file so the webhook domain can be verified
  // (required before Google will deliver push). Content comes from env.
  if (method === 'GET' && /^\/google[0-9a-z]+\.html$/i.test(pathname)) {
    const fileName = process.env.GOOGLE_SITE_VERIFICATION_FILE;
    const content = process.env.GOOGLE_SITE_VERIFICATION_CONTENT;
    if (fileName && content && pathname === `/${fileName}`) {
      res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
      res.end(content);
      return true;
    }
  }

  // ── Calendar sync: manual trigger + diagnostics ───────────
  // Forces one poll pass instead of waiting for the interval. Returns how many
  // connections were processed; check server logs for per-event detail.
  if (pathname === '/api/visitor/calendar/sync-now' && (method === 'POST' || method === 'GET')) {
    const secret = process.env.VISITOR_CALENDAR_INBOUND_SECRET;
    if (secret) {
      const provided = (req.headers['x-calendar-secret'] as string | undefined) ?? (query.secret as string | undefined);
      if (provided !== secret) { json(res, 401, { error: 'unauthorized' }); return true; }
    }
    const connections = await listActiveOAuthConnections();
    const summary = connections.map((c) => ({ host: c.host_email, hasToken: !!c.refresh_token, syncToken: !!c.sync_token, status: c.status }));
    try {
      const result = await runCalendarSyncOnce();
      json(res, 200, { ok: true, ...result, connections: summary });
    } catch (err) {
      json(res, 500, { error: err instanceof Error ? err.message : 'sync failed', connections: summary });
    }
    return true;
  }

  // ── Add-on email preview (HTML popup) ─────────────────────
  // Opened as a browser OVERLAY popup from the card (CardService OpenLink), which
  // cannot send the Bearer ID token — so this GET is authorized by a short-lived
  // HMAC-signed token instead. Returns the SAME branded HTML we'd actually send.
  if (pathname === '/api/visitor/calendar/addon/preview-html' && method === 'GET') {
    const payload = verifyPreviewToken(typeof query.t === 'string' ? query.t : undefined);
    if (!payload) {
      res.writeHead(401, { 'Content-Type': 'text/html; charset=utf-8' });
      res.end('<p style="font-family:sans-serif;padding:24px">Preview link expired. Reopen the card and try again.</p>');
      return true;
    }
    const iCalUid = String(payload.iCalUid ?? '');
    const visitorEmail = String(payload.visitorEmail ?? '').toLowerCase();
    const draft = iCalUid ? await getDraft(iCalUid) : null;
    const guest = draft?.roster.find((g) => g.email.toLowerCase() === visitorEmail);
    if (!draft || !guest) {
      res.writeHead(404, { 'Content-Type': 'text/html; charset=utf-8' });
      res.end('<p style="font-family:sans-serif;padding:24px">This guest is no longer in the draft.</p>');
      return true;
    }
    try {
      const data: PassEmailData = {
        visitorName: guest.name || visitorEmail,
        hostName: String(payload.hostName ?? ''),
        purpose: draft.title,
        validFrom: draft.eventStart,
        validUntil: draft.eventEnd,
        passUrl: 'https://preview.example/pass/preview',
        emailTemplateKey: guest.emailTemplateKey,
      };
      const rendered = await renderPassEmailPreview(data);
      // Wrap the email HTML in a minimal chrome so the popup reads as a preview.
      const banner = `<div style="font-family:sans-serif;background:#f1f3f4;color:#5f6368;padding:8px 16px;font-size:13px;border-bottom:1px solid #dadce0">Preview · Subject: ${escapeHtml(rendered.subject)} · To: ${escapeHtml(visitorEmail)}</div>`;
      res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
      res.end(banner + rendered.html);
    } catch (err) {
      console.error('[Addon] preview-html failed:', err);
      res.writeHead(500, { 'Content-Type': 'text/html; charset=utf-8' });
      res.end('<p style="font-family:sans-serif;padding:24px">Could not render the preview.</p>');
    }
    return true;
  }

  // ── Auxilio Workspace add-on (calendar visitor add-on) ────
  // Card-action endpoints. Authenticated by the add-on's Google ID token (NOT an
  // admin session), and strictly additive — they reuse createVisitorInvite /
  // renderPassEmail / cancelInvitationById without touching the dashboard/Slack
  // routes. Spec: spec/2026-06-16_calendar_addon_register_endpoint.md.
  if (pathname.startsWith('/api/visitor/calendar/addon/')) {
    const identity = await verifyAddonIdToken(req.headers.authorization);
    if (!identity) {
      json(res, 401, { error: 'invalid or missing add-on identity token' });
      return true;
    }
    if (!isInternalHostEmail(identity.email)) {
      json(res, 403, { error: 'host domain not allowed' });
      return true;
    }

    // POST /addon/draft — load (or lazily build + pre-fill) the Visit Draft.
    if (pathname === '/api/visitor/calendar/addon/draft' && method === 'POST') {
      const body = await readBodyJson(req);
      const iCalUid = String(body.iCalUid ?? '').trim();
      if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
      const attendees = Array.isArray(body.attendees)
        ? (body.attendees as { email: string; name?: string }[]).filter((a) => a && typeof a.email === 'string')
        : [];
      // Card-open path → trusted, complete attendee list → reconcile removals
      // (drop + cancel guests removed from the event). Plan §8B.
      const draft = await getOrCreateDraft({
        iCalUid,
        providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
        title: body.title ? String(body.title) : undefined,
        hostEmail: identity.email,
        attendees,
        eventStart: body.start ? String(body.start) : undefined,
        eventEnd: body.end ? String(body.end) : undefined,
        location: body.location ? String(body.location) : undefined,
      }, { reconcileRemovals: true });

      // Gap A — link this event for background lifecycle (move/delete via the watch),
      // but only when X is the event ORGANIZER (don't attach lifecycle to meetings
      // X was merely invited to) and a pass actually exists for it. Keyed on the
      // real iCalUid so the watch's ingest finds it. Reuses the D8 link writer.
      const organizerEmail = body.organizerEmail ? String(body.organizerEmail).toLowerCase() : '';
      const isOrganizer = !!organizerEmail && organizerEmail === identity.email.toLowerCase();
      const sentIds = draft.roster.filter((g) => g.status === 'sent' && g.invitationId).map((g) => g.invitationId as string);
      if (isOrganizer && sentIds.length > 0) {
        await recordInvitationCalendarLink({
          iCalUid,
          providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
          organizerEmail: identity.email,
          invitationIds: sentIds,
          source: 'addon-link',
          eventStart: draft.eventStart ?? null,
          eventEnd: draft.eventEnd ?? null,
        }).catch((e) => console.warn('[Addon] event link failed:', e));
      }

      // Gap C — tell the card whether background auto-sync (move/delete) is active.
      // Connected → seamless. Not connected → the card offers a one-tap Connect.
      const connected = await isCalendarConnected(identity.email).catch(() => false);
      const calendarSync = {
        connected,
        canConnect: isCalendarOAuthConfigured(),
        // Only meaningful to prompt when X owns the event (lifecycle attaches to it).
        relevant: isOrganizer,
        connectUrl: !connected && isCalendarOAuthConfigured()
          ? connectStartUrl({ email: identity.email })
          : undefined,
      };

      // Host-safe email-template picker list (NOT the admin endpoint — a host has no
      // visitor.templates.view permission). Active email-channel templates only, with
      // the engine default flagged so the card can pre-select it. The card only shows
      // the dropdown when there's a real choice (≥2); one template → no clutter.
      const emailTemplates = await listAddonEmailTemplates();

      json(res, 200, { ...draft, calendarSync, emailTemplates });
      return true;
    }

    // POST /addon/status — read-only batch check: which of these events already
    // have at least one active (sent) pass. Lets a client (e.g. the Chrome
    // extension's background poll) suppress nudges for events already handled
    // through ANY surface (add-on, another device), not just locally. Unlike
    // /draft this is side-effect-free — no lazy draft creation, no link
    // recording — so it is cheap and safe to poll. Capped to bound the work.
    if (pathname === '/api/visitor/calendar/addon/status' && method === 'POST') {
      const body = await readBodyJson(req);
      const iCalUids = (Array.isArray(body.iCalUids) ? body.iCalUids : [])
        .map((v: unknown) => String(v ?? '').trim())
        .filter(Boolean)
        .slice(0, 100);
      const active: string[] = [];
      for (const uid of iCalUids) {
        const draft = await getDraft(uid);
        if (draft?.roster.some((g) => g.status === 'sent')) active.push(uid);
      }
      json(res, 200, { active });
      return true;
    }

    // PATCH /addon/draft — persist a host edit (include toggle / name / phone / templates / location).
    if (pathname === '/api/visitor/calendar/addon/draft' && method === 'PATCH') {
      const body = await readBodyJson(req);
      const iCalUid = String(body.iCalUid ?? '').trim();
      if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
      const updated = await patchDraft(iCalUid, body.patch as DraftPatch | undefined);
      if (!updated) { json(res, 404, { error: 'draft not found' }); return true; }
      json(res, 200, updated);
      return true;
    }

    // POST /addon/preview — render the invite email for one guest (no send).
    if (pathname === '/api/visitor/calendar/addon/preview' && method === 'POST') {
      const body = await readBodyJson(req);
      const iCalUid = String(body.iCalUid ?? '').trim();
      const visitorEmail = String(body.visitorEmail ?? '').trim().toLowerCase();
      const draft = iCalUid ? await getDraft(iCalUid) : null;
      const guest = draft?.roster.find((g) => g.email.toLowerCase() === visitorEmail);
      if (!draft || !guest) { json(res, 404, { error: 'guest not found in draft' }); return true; }
      try {
        const hostName = await resolveHostDisplayName(identity.email, identity.name);
        const data: PassEmailData = {
          visitorName: guest.name || visitorEmail,
          hostName,
          purpose: draft.title,
          validFrom: draft.eventStart,
          validUntil: draft.eventEnd,
          passUrl: 'https://preview.example/pass/preview',
          emailTemplateKey: guest.emailTemplateKey,
        };
        const rendered = await renderPassEmailPreview(data);
        // Signed token so the card can open the HTML popup without a Bearer. 30-min TTL:
        // the add-on now mints this at confirm-card BUILD time (not on the Preview click)
        // so the link can open directly and dodge the popup blocker — it must outlive the
        // host reading the confirm card. Expired → preview-html shows a "reopen" message.
        const previewToken = signPreviewToken({
          iCalUid,
          visitorEmail,
          hostName,
          exp: Date.now() + 30 * 60_000,
        });
        json(res, 200, { subject: rendered.subject, html: rendered.html, text: rendered.text, previewToken });
      } catch (err) {
        console.error('[Addon] preview failed:', err);
        json(res, 500, { error: 'Preview failed' });
      }
      return true;
    }

    // POST /addon/send (and /addon/apply alias) — reconcile passes to the toggles:
    // create for newly-included guests, cancel for newly-excluded ones, keep the
    // rest. Used by both "Send passes" (Setup) and "Update passes" (Manage).
    if ((pathname === '/api/visitor/calendar/addon/send' || pathname === '/api/visitor/calendar/addon/apply') && method === 'POST') {
      const body = await readBodyJson(req);
      const iCalUid = String(body.iCalUid ?? '').trim();
      const draft = iCalUid ? await getDraft(iCalUid) : null;
      if (!draft) { json(res, 404, { error: 'draft not found' }); return true; }
      // Self-correct the event window from the times the card re-resolves at send.
      // The draft-open's time fetch (Calendar.Events.get) is flaky on a just-created
      // event, so the stored draft can lack start/end → applyDraft would fail every
      // guest with EVENT_TIME_MISSING. Trust fresh times when the card provides them.
      if (body.start) draft.eventStart = String(body.start);
      if (body.end) draft.eventEnd = String(body.end);
      const result = await applyDraft(draft, { hostName: identity.name });
      // Record the ledger from the active set; draft_authoritative so passive
      // producers reissue/cancel from the curated roster on move/delete.
      await recordDraftMaterialization({
        iCalUid,
        providerEventId: draft.providerEventId,
        organizerEmail: identity.email,
        invitationIds: result.invitationIds,
        eventStart: draft.eventStart ?? null,
        eventEnd: draft.eventEnd ?? null,
      });
      json(res, 200, {
        iCalUid,
        created: result.created,
        cancelled: result.cancelled,
        updated: result.updated,
        failed: result.failed,
        activeCount: result.invitationIds.length,
        draft: result.draft,
      });
      return true;
    }

    // POST /addon/cancel-guest — cancel one guest's invite.
    if (pathname === '/api/visitor/calendar/addon/cancel-guest' && method === 'POST') {
      const body = await readBodyJson(req);
      const invitationId = String(body.invitationId ?? '').trim();
      if (!invitationId) { json(res, 422, { error: 'invitationId required' }); return true; }
      const cancelled = await cancelInvitationById(invitationId).catch(() => false);
      // Fire the cancellation notice (guest + host emails via the
      // visitor.invite_cancelled flow), same as every other cancel surface —
      // otherwise a per-guest cancel from the extension is silent. Scrub the id
      // from any calendar link/draft first so a later event move can't resurrect
      // it. Best-effort; never fail the cancel on a notify error.
      if (cancelled) {
        await unlinkInvitationFromCalendar(invitationId).catch((e) => console.warn('[Addon] cancel-guest unlink failed:', e));
        await markDraftGuestCancelledByInvitationId(invitationId).catch((e) => console.warn('[Addon] cancel-guest draft-mark failed:', e));
        await notifyInviteCancelled(invitationId, {
          cancelledBy: identity.name,
          reason: 'The host cancelled your visitor pass.',
        }).catch((e) => console.warn('[Addon] cancel-guest notify failed:', e));
      }
      json(res, 200, { invitationId, cancelled });
      return true;
    }

    // POST /addon/connect-calendar — one-consent calendar connect from the Chrome
    // extension's hybrid sign-in. Exchanges the auth code for a refresh token so the
    // background poll keeps passes in sync when the panel is closed. Best-effort:
    // always 200 (sign-in must not fail on this); the connectUrl CTA is the fallback.
    if (pathname === '/api/visitor/calendar/addon/connect-calendar' && method === 'POST') {
      if (!isAuxilioExtensionOAuthConfigured()) {
        json(res, 200, { connected: false });
        return true;
      }
      const body = await readBodyJson(req);
      const code = String(body.code ?? '').trim();
      const redirectUri = String(body.redirectUri ?? '').trim();
      if (!code || !redirectUri) { json(res, 422, { error: 'code and redirectUri required' }); return true; }

      // Never downgrade a host who already has offline access (e.g. Slack rw connect) —
      // any connected refresh token already powers the read poll. (D7)
      const existing = await getCalendarConnection(identity.email).catch(() => null);
      if (existing?.status === 'connected' && existing.refresh_token) {
        json(res, 200, { connected: true });
        return true;
      }
      try {
        const { refreshToken } = await exchangeExtensionCalendarCode(code, redirectUri);
        if (!refreshToken) { json(res, 200, { connected: false }); return true; }
        await upsertCalendarConnection({
          email: identity.email,
          refreshToken,
          scopeVersion: EXTENSION_SCOPE_VERSION,
        });
        // Register a push channel if webhooks are configured (no-op otherwise; poll covers it).
        void ensureWatchForHost(identity.email).catch((err) => console.warn('[Addon] watch register failed:', err));
        json(res, 200, { connected: true });
      } catch (err) {
        console.error('[Addon] connect-calendar failed:', err);
        json(res, 200, { connected: false });
      }
      return true;
    }

    json(res, 404, { error: 'unknown add-on route' });
    return true;
  }

  // ── Calendar OAuth connect: kick off the flow ─────────────
  // The Slack App Home / first-DM button points here with a signed `s` carrying
  // the host's email (+ slack id). We verify it, then 302 to Google consent with
  // login_hint pre-selecting the host's account.
  if (pathname === '/api/visitor/calendar/connect/start' && method === 'GET') {
    if (!isCalendarOAuthConfigured()) {
      json(res, 503, { error: 'Calendar OAuth is not configured.' });
      return true;
    }
    const stateParam = typeof query.s === 'string' ? query.s : undefined;
    const payload = verifyCalendarState(stateParam);
    if (!payload || !stateParam) {
      json(res, 400, { error: 'Invalid or expired connect link. Please reopen it from Slack.' });
      return true;
    }

