// POST /addon/cancel-guest — cancel one guest's invite.
if (pathname === '/api/visitor/calendar/addon/cancel-guest' && method === 'POST') {
  const body = await readBodyJson(req);
  const invitationId = String(body.invitationId ?? '').trim();
  if (!invitationId) { json(res, 422, { error: 'invitationId required' }); return true; }
  const cancelled = await cancelInvitationById(invitationId).catch(() => false);
  // Fire the cancellation notice (guest + host emails via the
  // visitor.invite_cancelled flow), same as every other cancel surface —
  // otherwise a per-guest cancel from the extension is silent. Scrub the id
  // from any calendar link/draft first so a later event move can't resurrect
  // it. Best-effort; never fail the cancel on a notify error.
  if (cancelled) {
    await unlinkInvitationFromCalendar(invitationId).catch((e) => console.warn('[Addon] cancel-guest unlink failed:', e));
    await markDraftGuestCancelledByInvitationId(invitationId).catch((e) => console.warn('[Addon] cancel-guest draft-mark failed:', e));
    await notifyInviteCancelled(invitationId, {
      cancelledBy: identity.name,
      reason: 'The host cancelled your visitor pass.',
    }).catch((e) => console.warn('[Addon] cancel-guest notify failed:', e));
  }
  json(res, 200, { invitationId, cancelled });
  return true;
}

