113	/**
114	 * Background-enrich the draft: for guests we only have an email-derived fallback
115	 * name for (`nameIsFallback`), resolve the real name + photo from the host's Google
116	 * contacts and merge them into the cached draft. Non-destructive — it only rewrites
117	 * cache fields; RosterRow adopts an updated name/photo solely when the host hasn't
118	 * edited that field, so a late resolve never clobbers a live correction. One-shot
119	 * per distinct set of pending guests (cached in the background after the first run).
120	 */
121	export function useResolveGuestNames(draft: DraftResponse | undefined) {
122	  const qc = useQueryClient();
123	  const iCalUid = draft?.iCalUid;
124	  const pending = (draft?.roster ?? [])
125	    .filter((g) => g.nameIsFallback)
126	    .map((g) => g.email.toLowerCase())
127	    .sort();
128	  // Stable key so the effect fires only when the pending set actually changes.
129	  const key = pending.join('|');
130	
131	  // DIAGNOSTIC: what the panel loaded + who needs resolving. Reveals whether the
132	  // resolver even runs (pending non-empty) and whether nameIsFallback is set.
133	  console.log(
134	    '[auxilio] resolve-names: roster',
135	    (draft?.roster ?? []).map((g) => ({ email: g.email, name: g.name, fb: g.nameIsFallback })),
136	    '| pending', pending,
137	  );
138	
139	  useEffect(() => {
140	    if (!iCalUid || pending.length === 0) return;
141	    let cancelled = false;
142	    rpc({ type: 'RESOLVE_GUESTS', emails: pending })
143	      .then((resolved) => {
144	        console.log('[auxilio] resolve-names: RESOLVE_GUESTS returned', resolved);
145	        if (cancelled || !resolved || Object.keys(resolved).length === 0) return;
146	        // Names we upgraded from a fallback → persist them to the engine so the
147	        // materialized PASS + EMAIL use the real name, not the email-derived
148	        // fallback. Resolution is client-side only, so without this the engine's
