export async function checkoutSession(
  sessionId: string,
  checkoutTime?: string,
): Promise<number> {
  const db = await getDb();
  const session = await getSessionById(sessionId);
  if (!session) return 0;

  // Parse checkin time robustly — stored as ISO 8601
  const checkinMs = new Date(session.checkin_time).getTime();
  const effectiveCheckout = checkoutTime ?? new Date().toISOString();
  const nowMs = new Date(effectiveCheckout).getTime();
  // Guard against NaN (corrupt stored value) — default to 0
  const durationMinutes = Number.isFinite(checkinMs)
    && Number.isFinite(nowMs)
    ? Math.max(0, Math.round((nowMs - checkinMs) / 60000))
    : 0;

  await db.execute({
    sql: `UPDATE visitor_sessions
          SET checkout_time = ?, duration_minutes = ?
          WHERE id = ?`,
    args: [effectiveCheckout, durationMinutes, sessionId],
  });

  return durationMinutes;
}

