/** Check-in status for a batch of invitations, for the calendar surfaces' "X of Y
 *  checked in" feedback. Returns one entry per invitation that has at least one
 *  visitor session: the latest check-in time, and whether a session is still open
 *  (currently inside vs already checked out). Invitations with no session are absent
 *  from the map (= not arrived yet). */
export async function getCheckinByInvitationIds(
  ids: string[],
): Promise<Map<string, { checkinTime: string; inside: boolean }>> {
  const result = new Map<string, { checkinTime: string; inside: boolean }>();
  const clean = [...new Set(ids.filter(Boolean))];
  if (clean.length === 0) return result;
  const db = await getDb();
  const placeholders = clean.map(() => '?').join(',');
  const rows = await db.execute({
    sql: `SELECT invitation_id,
                 MAX(checkin_time) AS checkin_time,
                 BOOL_OR(checkout_time IS NULL) AS inside
          FROM visitor_sessions
          WHERE invitation_id IN (${placeholders})
          GROUP BY invitation_id`,
    args: clean,
  });
  for (const r of rows.rows as unknown as {
    invitation_id: string;
    checkin_time: string | null;
    inside: boolean | number | null;
  }[]) {
    if (!r.invitation_id || !r.checkin_time) continue;
    result.set(r.invitation_id, {
      checkinTime: r.checkin_time,
      inside: r.inside === true || r.inside === 1,
    });
  }
  return result;
}

