      : !hasName && !hasPhone
        ? 'Add phone and name'
        : hasPhone
          ? 'Add name'
          : 'Add phone';

  // Switch is no longer locked once a pass is sent: toggling off cancels on the
  // next update (mirrors the add-on), toggling back on re-issues.
  const switchLabel = sent
    ? guest.include
