export async function createVisitorInvite(
  input: CreateInvitationInput,
): Promise<CreateInviteResult> {
  const tier = input.approvalTier ?? 'invited';

  // F2 — same-workspace guard: a planned ('invited') pass for an internal colleague
  // at the host's own/unknown office is soft-blocked unless the caller overrides.
  // Walk-ins (physically present) and non-internal/different-office guests pass.
  if (tier === 'invited' && !input.allowInternalColleague
    && isSameWorkspaceLocalColleague(input.visitorEmail, input.hostEmail)) {
    throw new SameOfficeColleagueError(input.visitorEmail ?? '');
  }

  const status = input.approvalStatus ?? (tier === 'invited' ? 'approved' : 'pending');
  const validFrom = resolveDefaultValidFrom({ ...input, approvalTier: tier });
  const validUntil = input.validUntil ?? computeExpiry(tier, input.expectedDate);
  const validFromDate = new Date(validFrom);
  const validUntilDate = new Date(validUntil);

  if (Number.isNaN(validFromDate.getTime())) {
    throw new Error('Pass start time is invalid.');
  }
  if (Number.isNaN(validUntilDate.getTime())) {
    throw new Error('Pass end time is invalid.');
  }
  if (validUntilDate <= validFromDate) {
    throw new Error('Pass end time must be after the start time.');
  }

  if (tier === 'invited') {
    const todayIST = getCurrentISTDate();
    if (input.expectedDate < todayIST) {
      throw new Error('Invitation date cannot be in the past.');
    }
    if (input.validUntil && validUntilDate < new Date()) {
      throw new Error('Invitation end time cannot be in the past.');
    }
  }

  // Generate QR with embedded visitor data for offline guard scanning.
  // validUntil overrides the auto-computed expiry when explicitly set.
  const qr = await generateVisitorQR(tier, input.expectedDate, input.qrToken, {
    visitorName: input.visitorName,
    purpose: input.purpose,
    hostName: input.hostEmployeeName,
    phone: input.visitorPhone,
    validFrom,
    expiresAt: validUntil,
  });

  // Persist invitation
  const invitationId = await createInvitation({
    ...input,
    approvalStatus: status,
    approvalTier: tier,
    qrToken: qr.token,
    qrUrl: qr.url,
    expiresAt: qr.expiresAt,
    validUntil,
    validFrom,
  });

  // qr_generated is an internal system event (no notifications) so it
  // stays imperative — it isn't a side-effect admins need to customize.
  await logAction({
    action: 'qr_generated',
    actorType: 'system',
    invitationId,
    metadata: { token: qr.token, expiresAt: qr.expiresAt },
