      host: { name: hostName },
      cancelledBy,
      reason: opts.reason ?? '',
      'time.hour': new Date().getHours(),
    };
    await runVisitorFlowRules('visitor.invite_cancelled', payload);
    await Promise.all([dispatchFlowEmails(payload), dispatchFlowNotifications(payload)]);
  } catch (err) {
    console.warn('[InviteManager] notifyInviteCancelled failed:', err);
  }
}

