export function isAuxilioExtensionOAuthConfigured(): boolean {
  return !!(auxilioExtensionOauth.clientId() && auxilioExtensionOauth.clientSecret());
}

function callbackUrl(): string {
  const origin = (googleOauthConfig.publicOrigin() ?? '').replace(/\/$/, '');
  if (!origin) throw new Error('GOOGLE_OAUTH_PUBLIC_ORIGIN is not configured');
  return `${origin}/api/visitor/calendar/connect/callback`;
}

function buildClient() {
  const clientId = googleOauthConfig.clientId();
  const clientSecret = googleOauthConfig.clientSecret();
  if (!clientId || !clientSecret) throw new Error('Google OAuth client credentials are not configured');
  return new google.auth.OAuth2(clientId, clientSecret, callbackUrl());
}

// ─── Signed state (carries host binding, no server-side store) ────────

export interface CalendarStatePayload {
  email: string;
  slackUserId?: string;
}

export function issueCalendarState(payload: CalendarStatePayload): string {
  const body = Buffer.from(JSON.stringify({ ...payload, exp: Date.now() + STATE_TTL_MS })).toString('base64url');
  const sig = createHmac('sha256', stateSecret()).update(body).digest('base64url');
  return `${body}.${sig}`;
}

export function verifyCalendarState(state: string | undefined): CalendarStatePayload | null {
  if (!state) return null;
  const parts = state.split('.');
  if (parts.length !== 2) return null;
  const [body, sig] = parts as [string, string];
  const expected = createHmac('sha256', stateSecret()).update(body).digest('base64url');
  const a = Buffer.from(sig, 'utf8');
  const b = Buffer.from(expected, 'utf8');
  if (a.length !== b.length || !timingSafeEqual(a, b)) return null;
  try {
    const parsed = JSON.parse(Buffer.from(body, 'base64url').toString('utf8')) as CalendarStatePayload & { exp: number };
    if (!parsed.exp || parsed.exp < Date.now() || !parsed.email) return null;
    return { email: parsed.email.toLowerCase(), slackUserId: parsed.slackUserId };
  } catch {
    return null;
  }
}

/** The browser URL the Slack button points at (our /start, not Google directly). */
export function connectStartUrl(payload: CalendarStatePayload): string {
  const origin = (googleOauthConfig.publicOrigin() ?? '').replace(/\/$/, '');
  return `${origin}/api/visitor/calendar/connect/start?s=${encodeURIComponent(issueCalendarState(payload))}`;
}

/** URL for the Slack "Disconnect" button → our disconnect route. */
export function disconnectUrl(payload: CalendarStatePayload): string {
  const origin = (googleOauthConfig.publicOrigin() ?? '').replace(/\/$/, '');
  return `${origin}/api/visitor/calendar/connect/disconnect?s=${encodeURIComponent(issueCalendarState(payload))}`;
}

/** Google consent URL. login_hint pre-selects the host's account (research doc §8). */
export function buildCalendarAuthUrl(state: string, loginHint?: string): string {
  const client = buildClient();
  return client.generateAuthUrl({
    access_type: 'offline',   // required for a refresh token
    prompt: 'consent',         // guarantees refresh token even on re-auth
    scope: CALENDAR_SCOPES,
    state,
    include_granted_scopes: true,
    ...(loginHint ? { login_hint: loginHint } : {}),
  });
}

export interface CalendarTokenResult {
  refreshToken?: string;
}

export async function exchangeCalendarCode(code: string): Promise<CalendarTokenResult> {
  const client = buildClient();
  const { tokens } = await client.getToken(code);
  return { refreshToken: tokens.refresh_token ?? undefined };
}

/**
 * Exchange the Chrome extension's hybrid-flow auth code for a refresh token, using
 * the EXTENSION's Web client (id+secret) and the same redirect URI the extension used
 * (chrome.identity.getRedirectURL()). The refresh token is bound to this client, so it
 * must later be refreshed via clientForConnection() (extension branch).
 */
export async function exchangeExtensionCalendarCode(code: string, redirectUri: string): Promise<CalendarTokenResult> {
  const clientId = auxilioExtensionOauth.clientId();
  const clientSecret = auxilioExtensionOauth.clientSecret();
  if (!clientId || !clientSecret) throw new Error('Auxilio extension OAuth client credentials are not configured');
  const client = new google.auth.OAuth2(clientId, clientSecret, redirectUri);
